export const LoginForm = () => {
  const router = useRouter();

  const searchParams = useSearchParams();

  const [githubPending, startGithubTransition] = useTransition();
  const [googlePending, startGoogleTransition] = useTransition();
  const [emailPending, startEmailTransition] = useTransition();
  const [phonePending, startPhoneTransition] = useTransition();
  // const [firstName, setFirstName] = useState("");
  // const [lastName, setLastName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [phoneNumber, setPhoneNumber] = useState("");
  const [phoneOtp, setPhoneOtp] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [activeTab, setActiveTab] = useState("email");

  const workspaceId = searchParams.get("workspaceId");
  const role = searchParams.get("role");
  const inviteEmail = searchParams.get("email");

  useEffect(() => {
    if (inviteEmail) {
      setEmail(inviteEmail);
    }
  }, [inviteEmail]);

  async function signInWithGithub() {
    startGithubTransition(async () => {
      const callbackURL = workspaceId && role
        ? `/api/v1/workspaces/verify?workspaceId=${workspaceId}&role=${role}`
        : "/w";

      await authClient.signIn.social({
        provider: "github",
        callbackURL,
        fetchOptions: {
          onSuccess: (ctx) => {
            toast.success("Signed in with Github, you will be redirected...");
          },
          onError: (error) => {
            toast.error("Internal server error");
          },
        },
      });
    });
  }

  async function signInWithGoogle() {
    startGoogleTransition(async () => {
      const callbackURL = workspaceId && role
        ? `/api/v1/workspaces/verify?workspaceId=${workspaceId}&role=${role}`
        : "/w";

      await authClient.signIn.social({
        provider: "google",
        callbackURL,
        fetchOptions: {
          onSuccess: (ctx) => {
            toast.success("Signed in with google, you will be redirected...");
          },
          onError: (error) => {
            toast.error("Internal server error");
          },
        },
      });
    });
  }

  async function signInWithEmail() {
    startEmailTransition(async () => {
      try {
        const callbackURL = workspaceId && role
          ? `/api/v1/workspaces/verify?workspaceId=${workspaceId}&role=${role}`
          : "/w";

        await authClient.signIn.email({
          email,
          password,
          callbackURL,
          fetchOptions: {
            onSuccess: (ctx) => {

              toast.success("Signed in successfully!");
              window.location.href = callbackURL;
            },
            onError: (ctx) => {
              const isNoPassword = ctx.error.code === "USER_HAS_NO_PASSWORD" ||
                ctx.error.message.toLowerCase().includes("password") &&
                (ctx.error.message.toLowerCase().includes("not set") || ctx.error.message.toLowerCase().includes("no"));

              if (isNoPassword) {
                toast.error("No password found for this account. Please create a password to login with email.", {
                  duration: 5000,
                });
                // Redirect to forgot password to trigger the reset flow
                setTimeout(() => {
                  router.push(`/forgot-password?email=${encodeURIComponent(email)}`);
                }, 2000);
              } else {
                toast.error(ctx.error.message || "Failed to sign in");
              }
            },
          },
        });
      } catch (error: any) {
        toast.error("An error occurred during sign in");
        console.error("[Login Error Details]:", {
          message: error?.message,
          error: error,
          stack: error?.stack
        });
      }
    });
  }

  async function sendPhoneOtp() {
    if (!phoneNumber) {
      toast.error("Please enter a phone number");
      return;
    }

    startPhoneTransition(async () => {
      try {
        // Check if user exists before sending OTP
        const { exists } = await checkUserExistsByPhone(phoneNumber);
        if (!exists) {
          toast.error("This phone number is not registered. Please contact your administrator.", {
            duration: 5000,
          });
          return;
        }

        await authClient.phoneNumber.sendOtp({
          phoneNumber,
          fetchOptions: {
            onSuccess: () => {
              setOtpSent(true);
              toast.success("OTP sent to your phone!");
            },
            onError: (ctx: any) => {
              toast.error(ctx.error.message || "Failed to send OTP");
            },
          },
        });
      } catch (error) {
        toast.error("An error occurred while sending OTP");
        console.error(error);
      }
    });
  }

  // async function signInWithPhone() {
  //   if (!phoneOtp || phoneOtp.length !== 6) {
  //     toast.error("Please enter a valid 6-digit OTP");
  //     return;
  //   }

  //   startPhoneTransition(async () => {
  //     try {
  //       const callbackURL = workspaceId && role
  //         ? `/api/v1/workspaces/verify?workspaceId=${workspaceId}&role=${role}`
  //         : "/w";

  //       await authClient.phoneNumber.verify({
  //         phoneNumber,
  //         code: phoneOtp,
  //         fetchOptions: {
  //           onSuccess: (ctx) => {
  
  //             toast.success("Signed in successfully!");
  //             window.location.href = callbackURL;
  //           },
  //           onError: (ctx) => {
  //             toast.error(ctx.error.message || "Failed to sign in");
  //           },
  //         },
  //       });
  //     } catch (error) {
  //       toast.error("An error occurred during sign in");
  //       console.error(error);
  //     }
  //   });
  // }

  return (
    <Card className="py-8">
      <CardHeader>
        <CardTitle className="text-xl">
          {workspaceId ? "Join Workspace" : "Welcome back!"}
        </CardTitle>
        <CardDescription>
          {workspaceId
            ? "Sign in to join the workspace"
            : "Login with email and password"}
        </CardDescription>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
          {/* <TabsList className="grid w-full grid-cols-2 mb-4">
            <TabsTrigger value="email">
              <Mail className="size-3.5 mr-2" />
              Email
            </TabsTrigger>
            <TabsTrigger value="phone">
              <Phone className="size-3.5 mr-2" />
              Phone
            </TabsTrigger>
          </TabsList> */}

          <TabsContent value="email" className="space-y-4">
            <div className="grid gap-3">
              <div className="grid gap-2">
                <Label htmlFor="email">Email</Label>
                <Input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="your@email.com"
                  required
                />
              </div>

              <div className="grid gap-2">
                <div className="flex items-center justify-between">
                  <Label htmlFor="password">Password</Label>
                  <a
                    href="/forgot-password"
                    className="text-xs text-muted-foreground hover:text-primary underline-offset-4 hover:underline"
                  >
                    Forgot password?
                  </a>
                </div>
                <PasswordInput
                  id="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  required
                />
              </div>

              <Button
                onClick={signInWithEmail}
                disabled={emailPending || !email || !password}
                className="w-full"
              >
                {emailPending ? (
                  <>
                    <Loader2 className="size-4 animate-spin" />
                    <span>Signing in...</span>
                  </>
