                  </p>
                </div>
                <Button
                  onClick={signInWithPhone}
                  disabled={phonePending || phoneOtp.length !== 6}
                  className="w-full"
                >
                  {phonePending ? (
                    <>
                      <Loader2 className="size-4 animate-spin" />
                      <span>Verifying...</span>
