"use client";

import React from "react";
import Link from "next/link";
import Image from "next/image";
import { buttonVariants } from "@/components/ui/button";
import { authClient } from "@/lib/auth-client";
import ThemeToggle from "@/components/ui/theme-toggle";
import { UserDropdown } from "./userDropdown";
import { toast } from "sonner";
import { useRouter } from "next/navigation";
import { useTheme } from "next-themes";

interface iAppProps {
  session?: any; // Optional session from server
}

export function Navbar({ session: serverSession }: iAppProps) {
  const router = useRouter();
  const { data: session, isPending } = authClient.useSession();
  const { resolvedTheme } = useTheme();
  const [mounted, setMounted] = React.useState(false);

  React.useEffect(() => {
    setMounted(true);
  }, []);

  // Use client session if available, otherwise use server session
  const currentSession = session || serverSession;

  // Determine logo based on theme (with hydration handling)
  const isDark = mounted ? resolvedTheme === "dark" : false;
  const logoSrc = isDark ? "/logo-b.png" : "/logo-w.png";

  // Protected click handler for Workspace link
  const handleWorkspaceClick = (e: React.MouseEvent) => {
    e.preventDefault();

    if (isPending) {
      toast("Checking session...");
      return;
    }

    if (!currentSession) {
      toast.error("Please login to access your workspace");
      router.push("/sign-in?next=/workspace");
      return;
    }
    router.push("/w");
  };

  return (
    <header className="sticky top-0 z-50 w-full border bg-background/95 backdrop-blur-[backdrop-filter]:bg-background/60">
      <div className="container flex min-h-16 items-center mx-auto px-4 md:px-6 lg:px-8">
        <Link href="/" className="flex items-center space-x-2 mr-2 sm:mr-4">
          <Image
            src={logoSrc}
            alt="Logo"
            width={150}
            height={50}
            className="p-1 sm:p-2 w-[70px] sm:w-[110px] transition-opacity duration-300"
            priority
          />
        </Link>

        {/* desktop navigation */}
        <nav className="hidden md:flex md:flex-1 md:items-center md:justify-between">
          <div className="flex items-center space-x-6">
            <Link href="/" className="text-sm font-medium transition-colors hover:text-primary">
              Home
            </Link>

            <a
              href="/w"
              onClick={handleWorkspaceClick}
              className="text-sm font-medium transition-colors hover:text-primary cursor-pointer"
            >
              Workspace
            </a>
          </div>

          <div className="flex items-center space-x-4">
            <ThemeToggle />

            {isPending ? null : session ? (
              <UserDropdown
                email={session.user.email}
                image={session?.user.image || ""}
                name={
                  session?.user.name && session?.user.name.length > 0
                    ? session?.user.name
                    : session?.user.email.split("@")[0]
                }
              />
            ) : (
              <>
                <Link href="/sign-in" className={buttonVariants({ variant: "secondary" })}>
                  Login
                </Link>
                <Link href="/sign-in" className={buttonVariants()}>
                  Get Started
                </Link>
              </>
            )}
          </div>
        </nav>

        {/* mobile / small screens: simple layout (optional) */}
        <nav className="flex md:hidden flex-1 items-center justify-end gap-3">
          <ThemeToggle />
          {isPending ? null : session ? (
            <UserDropdown
              email={session.user.email}
              image={session?.user.image || ""}
              name={
                session?.user.name && session?.user.name.length > 0
                  ? session?.user.name
                  : session?.user.email.split("@")[0]
              }
            />
          ) : (
            <>
              <Link href="/sign-in" className={buttonVariants({ variant: "secondary" })}>
                Login
              </Link>
              <Link href="/sign-in" className={buttonVariants()}>
                Get Started
              </Link>
            </>
          )}
        </nav>
      </div>
    </header>
  );
};

export default Navbar;

"use client";

import { useSearchParams } from "next/navigation";
import { Suspense, useState } from "react";
import { Mail, AlertCircle, CheckCircle } from "lucide-react";
import { AppLoader } from "@/components/shared/app-loader";

function VerifyEmailContent() {
    const searchParams = useSearchParams();
    const error = searchParams.get("error");
    const [resendStatus, setResendStatus] = useState<"idle" | "loading" | "success" | "error">("idle");

    const handleResendEmail = async () => {
        setResendStatus("loading");

        try {
            // Call Better Auth's resend verification email endpoint
            const response = await fetch("/api/auth/send-verification-email", {
                method: "POST",
            });

            if (response.ok) {
                setResendStatus("success");
            } else {
                setResendStatus("error");
            }
        } catch (err) {
            setResendStatus("error");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 to-indigo-100 p-4">
            <div className="max-w-md w-full bg-white rounded-2xl shadow-xl p-8">
                {/* Icon */}
                <div className="flex justify-center mb-6">
                    <div className="w-20 h-20 bg-blue-100 rounded-full flex items-center justify-center">
                        <Mail className="w-10 h-10 text-blue-600" />
                    </div>
                </div>

                {/* Title */}
                <h1 className="text-3xl font-bold text-center text-gray-900 mb-4">
                    Verify Your Email
                </h1>

                {/* Error Message */}
                {error === "email-not-verified" && (
                    <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-lg flex items-start gap-3">
                        <AlertCircle className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
                        <div>
                            <p className="text-sm font-medium text-amber-900">
                                Email Verification Required
                            </p>
                            <p className="text-sm text-amber-700 mt-1">
                                You must verify your email address before accessing your workspace.
                            </p>
                        </div>
                    </div>
                )}

                {/* Main Message */}
                <div className="text-center mb-6">
                    <p className="text-gray-600 mb-4">
                        We've sent a verification email to your inbox. Please check your email and click the verification link to activate your account.
                    </p>

                    <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-4">
                        <p className="text-sm text-blue-900 font-medium mb-2">
                            📧 Check your inbox
                        </p>
                        <p className="text-xs text-blue-700">
                            The email may take a few minutes to arrive. Don't forget to check your spam folder!
                        </p>
                    </div>
                </div>

                {/* Resend Email Button */}
                <div className="space-y-4">
                    <button
                        onClick={handleResendEmail}
                        disabled={resendStatus === "loading" || resendStatus === "success"}
                        className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed text-white font-medium py-3 px-4 rounded-lg transition-colors duration-200 flex items-center justify-center gap-2"
                    >
                        {resendStatus === "loading" && (
                            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                        )}
                        {resendStatus === "success" ? "Email Sent!" : "Resend Verification Email"}
                    </button>

                    {resendStatus === "success" && (
                        <div className="p-3 bg-green-50 border border-green-200 rounded-lg flex items-center gap-2">
                            <CheckCircle className="w-5 h-5 text-green-600" />
                            <p className="text-sm text-green-800">
                                Verification email sent successfully! Please check your inbox.
                            </p>
                        </div>
                    )}

                    {resendStatus === "error" && (
                        <div className="p-3 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2">
                            <AlertCircle className="w-5 h-5 text-red-600" />
                            <p className="text-sm text-red-800">
                                Failed to send email. Please try again later.
                            </p>
                        </div>
                    )}

                    {/* Sign Out Link */}
                    <div className="text-center pt-4 border-t border-gray-200">
                        <a
                            href="/api/auth/sign-out"
                            className="text-sm text-gray-600 hover:text-gray-900 underline"
                        >
                            Sign out and use a different account
                        </a>
                    </div>
                </div>

                {/* Help Text */}
                <div className="mt-6 text-center">
                    <p className="text-xs text-gray-500">
                        Having trouble? Contact your workspace administrator for assistance.
                    </p>
                </div>
            </div>
        </div>
    );
}

export default function VerifyEmailPage() {
    return (
        <Suspense fallback={<AppLoader />}>
            <VerifyEmailContent />
        </Suspense>
    );
}

