"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { useState, useTransition, useEffect } from "react";
import { Resolver, useForm, useWatch } from "react-hook-form";
import { Loader2, PlusIcon } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { taskSchema, TaskSchemaType } from "@/lib/zodSchemas";
import { tryCatch } from "@/hooks/try-catch";
import { useConfetti } from "@/hooks/use-confetti";
import { toast } from "sonner";
import slugify from "slugify";
import { useTaskContext } from "@/app/w/[workspaceId]/_components/shared/task-context";
import { apiClient } from "@/lib/api-client";
import { getColorFromString } from "@/lib/colors/project-colors";

interface iAppProps {
    workspaceId: string;
    projectId?: string; // Optional for workspace-level
    level?: "workspace" | "project"; // Explicitly define the level
    projects?: { id: string; name: string; color?: string; }[]; // For workspace-level project selection
}

export const CreateTaskForm = ({
    projectId,
    level = "project", // Default to project level for backward compatibility
    projects = [], // Default to empty array
}: iAppProps) => {
    const [Pending, startTransition] = useTransition();
    const { triggerConfetti } = useConfetti();
    const [open, setOpen] = useState(false);
    const [autoSlugEnabled, setAutoSlugEnabled] = useState(true);
    const { addNewTask, updateTask, removeTask } = useTaskContext();

    const form = useForm<TaskSchemaType>({
        resolver: zodResolver(taskSchema) as unknown as Resolver<TaskSchemaType>,
        defaultValues: {
            name: "",
            taskSlug: "",
            projectId: projectId || (projects.length > 0 ? projects[0].id : ""),
        },
    })

    const watchedName = useWatch({
        control: form.control,
        name: "name",
    });

    const watchedTaskSlug = useWatch({
        control: form.control,
        name: "taskSlug",
    });

    useEffect(() => {
        if (!autoSlugEnabled || !open) return;
        if (!watchedName) return;

        const newSlug = slugify(watchedName, { lower: true, strict: true });
        form.setValue("taskSlug", newSlug, { shouldValidate: false });
    }, [watchedName, autoSlugEnabled, open, form]);

    useEffect(() => {
        if (open) {
            setAutoSlugEnabled(true);
        }
    }, [open]);

    function onSubmit(values: TaskSchemaType) {
        startTransition(async () => {
            const { data: result, error } = await tryCatch(apiClient.tasks.createTask(values));

            if (error) {
                toast.error(error.message);
                console.error(error);
                return;
            }

            if (result.status === "success" && result.data) {
                toast.success(result.message);
                triggerConfetti();
                setOpen(false);
                form.reset();
                // Task will be added to UI via RealtimeNotificationListener
            } else {
                toast.error(result.message);
            }
        });
    }

    return (
        <>
            <Dialog open={open} onOpenChange={setOpen}>
                <DialogTrigger asChild>
                    <Button
                        className="cursor-pointer">
                        Create Task
                    </Button>
                </DialogTrigger>
                <DialogContent >
                    <DialogHeader>
                        <DialogTitle>Create New Task</DialogTitle>
                    </DialogHeader>
                    <div className="mt-4">
                        <Form {...form}>
                            <form
                                onSubmit={form.handleSubmit(onSubmit, (errors) => console.log("Validation Errors:", errors))}
                                className="space-y-5"
                            >
                                <FormField
                                    control={form.control}
                                    name="name"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Task Title</FormLabel>
                                            <FormControl>
                                                <Input placeholder="Enter task title" {...field} />
                                            </FormControl>
                                            <input type="hidden" {...form.register("taskSlug")} />
                                            {watchedTaskSlug && (
                                                <p className="text-[10px] text-muted-foreground mt-1 px-1">
                                                    Slug: <span className="font-mono">{watchedTaskSlug}</span>
                                                </p>
                                            )}
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />

                                {/* Project Selection - Only for workspace level */}
                                {level === "workspace" && projects.length > 0 && (
                                    <FormField
                                        control={form.control}
                                        name="projectId"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Project</FormLabel>
                                                <Select onValueChange={field.onChange} value={field.value}>
                                                    <FormControl>
                                                        <SelectTrigger>
                                                            <SelectValue placeholder="Select a project" />
                                                        </SelectTrigger>
                                                    </FormControl>
                                                    <SelectContent>
                                                        {projects.map((project) => (
                                                            <SelectItem key={project.id} value={project.id}>
                                                                <div className="flex items-center gap-2">
                                                                    <div className="h-2 w-2 rounded-full border shadow-sm" style={{ backgroundColor: project.color || getColorFromString(project.name) }} />
                                                                    {project.name}
                                                                </div>
                                                            </SelectItem>
                                                        ))}
                                                    </SelectContent>
                                                </Select>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />
                                )}

                                <div className="flex flex-row items-center gap-4">
                                    <Button type="submit" disabled={Pending} className="cursor-pointer">
                                        {
                                            Pending ? (
                                                <>
                                                    Creating...
                                                    <Loader2 className="ml-1 h-4 w-4 animate-spin" />
                                                </>
                                            ) : (
                                                <>
                                                    Create Task
                                                    <PlusIcon className="ml-1" size={16} />
                                                </>
                                            )
                                        }
                                    </Button>
                                </div>
                            </form>
                        </Form>
                    </div>
                </DialogContent>
            </Dialog>
        </>
    );
};

"use client";

import { useState, useTransition, useEffect, useRef, useMemo, useCallback } from "react";
import { Loader2 } from "lucide-react";
import { GanttTask } from "../../../../../../../components/task/gantt/types";
import { useSubTaskSheetActions } from "@/contexts/subtask-sheet-context";
import type { WorkspaceTaskType } from "@/types/task";
import { GanttChart } from "@/components/task/gantt/gantt-chart";
import { GlobalFilterToolbar } from "@/components/task/shared/global-filter-toolbar";
import { TaskFilters } from "@/components/task/shared/types";
import { transformToGanttTasks, transformToGanttSubtasks } from "@/components/task/gantt/transform-tasks";
import { ProjectMembersType } from "@/types/project";
import { useFilterStore } from "@/lib/store/filter-store";

import { toast } from "sonner";
import { useWorkspaceLayout } from "@/app/w/[workspaceId]/_components/workspace-layout-context";
import { workspacesClient } from "@/lib/api-client/workspaces";

interface ProjectGanttClientProps {
    workspaceId: string;
    projectId: string;
    initialTasks: GanttTask[];
    allTasks: any[];
    subtaskDataMap: Record<string, WorkspaceTaskType>;
    members: ProjectMembersType;
    projectCounts?: Record<string, number>;
    currentUser?: { id: string };
    isShell?: boolean;
}

export function ProjectGanttClient({
    workspaceId,
    projectId,
    initialTasks,
    subtaskDataMap,
    members,
    projectCounts,
    currentUser,
}: ProjectGanttClientProps) {
    const { data: layoutData } = useWorkspaceLayout();
    const permissions = layoutData.permissions;
    const projects = layoutData.projects || [];
    const [tags, setTags] = useState<{ id: string; name: string }[]>([]);

    useEffect(() => {
        let mounted = true;
        const fetchTags = async () => {
            try {
                const workspaceTags = await workspacesClient.getTags(workspaceId);
                if (mounted) {
                    setTags(workspaceTags.map((t) => ({ id: t.id, name: t.name })));
                }
            } catch (error) {
                console.error("Failed to fetch tags for ProjectGanttClient:", error);
            }
        };
        fetchTags();
        return () => {
            mounted = false;
        };
    }, [workspaceId]);

    const [tasks, setTasks] = useState<GanttTask[]>(initialTasks);
    const [localTaskDataMap, setLocalTaskDataMap] = useState<Record<string, WorkspaceTaskType>>(subtaskDataMap);
    const [nextCursor, setNextCursor] = useState<any>(null);
    const [hasMore, setHasMore] = useState<boolean>(true);
    const [isLoadingMore, setIsLoadingMore] = useState<boolean>(false);
    const [loadingSubtasks, setLoadingSubtasks] = useState<Set<string>>(new Set());
    const fetchingIdsRef = useRef<Set<string>>(new Set());
    const fetchingSubtasksRef = useRef<Set<string>>(new Set()); // 🚀 NEW: Per-task lock for infinite scroll
    const expandedTaskIdsRef = useRef<Set<string>>(new Set());

    const { filters, setFilters, searchQuery, setSearchQuery, clearFilters } = useFilterStore();
    const [isPending, startTransition] = useTransition();

    // Use global subtask sheet context
    const { openSubTaskSheet } = useSubTaskSheetActions();

    // Handle subtask click

    const handleOpenSubTaskSheetFromGantt = useCallback((subtaskId: string) => {
        console.log("💎💎💎 [ProjectGanttClient] handleOpenSubTaskSheetFromGantt CALLED with ID:", subtaskId);
        console.log("[ProjectGanttClient] Map Size:", Object.keys(localTaskDataMap).length);
        const taskData = localTaskDataMap[subtaskId];

        if (taskData) {
            console.log("[ProjectGanttClient] Task found in map, calling openSubTaskSheet...");
            openSubTaskSheet(taskData);
        } else {
            console.warn("[ProjectGanttClient] Task data not found for sheet lookup. ID:", subtaskId, "Map Size:", Object.keys(localTaskDataMap).length);
            toast.error("Task details not found. Try refreshing.");
        }
    }, [localTaskDataMap, openSubTaskSheet]);

    console.log("[ProjectGanttClient] Rendering. handleOpenSubTaskSheetFromGantt present:", !!handleOpenSubTaskSheetFromGantt);

    const handleFilterChange = (newFilters: TaskFilters) => {
        startTransition(() => {
            setFilters(newFilters);
        });
    };

    const handleSearchChange = (query: string) => {
        startTransition(() => {
            setSearchQuery(query);
        });
    };

    // 🧹 Filter Reset Logic: Ensures a clean slate when navigating between different views
    useEffect(() => {
        return () => {
            clearFilters();
        };
    }, [clearFilters, workspaceId, projectId]);

    // ---------------------------------------------------------------------------
    // 🚀 REALTIME SYNC: Listen for Pusher-driven structural mutations
    // ---------------------------------------------------------------------------
    useEffect(() => {
        const handleRealtimeSync = (e: Event) => {
            const { action, record } = (e as CustomEvent).detail || {};
            if (!action || !record) return;

            // Relevance guard: only respond to events in this project
            const isRelevant = !record.projectId || record.projectId === projectId;
            if (!isRelevant) return;

            if (action === "TASK_CREATED" && !record.parentTaskId) {
                const newGanttTask = transformToGanttTasks([record]);
                if (newGanttTask.length === 0) return;
                setTasks((prev) => {
                    if (prev.some((t) => t.id === record.id)) return prev;
                    return [...prev, ...newGanttTask];
                });
            }

            if (action === "TASK_DELETED" && !record.parentTaskId) {
                setTasks((prev) => prev.filter((t) => t.id !== record.id));
            }

            if (action === "TASK_UPDATED" && !record.parentTaskId) {
                setTasks((prev) =>
                    prev.map((t) =>
                        t.id === record.id ? { ...t, ...transformToGanttTasks([record])[0] } : t,
                    ),
                );
            }

            if (action === "SUBTASK_CREATED" && record.parentTaskId) {
                setLocalTaskDataMap(prev => ({ ...prev, [record.id]: record }));
                const newSubtask = transformToGanttSubtasks([record]);
                setTasks((prev) =>
                    prev.map((t) => {
                        if (t.id !== record.parentTaskId) return t;
                        const updatedSubtasks = t.subtasks
                            ? t.subtasks.some((s) => s.id === record.id)
                                ? t.subtasks
                                : [...t.subtasks, ...newSubtask]
                            : t.subtasks;
                        return {
                            ...t,
                            subtasks: updatedSubtasks,
                            subtaskCount: (t.subtaskCount || 0) + 1,
                        };
                    }),
                );
            }

            if (action === "SUBTASK_DELETED" && record.parentTaskId) {
                setTasks((prev) =>
                    prev.map((t) => {
                        if (t.id !== record.parentTaskId) return t;
                        return {
                            ...t,
                            subtasks: t.subtasks?.filter((s) => s.id !== record.id),
                            subtaskCount: Math.max(0, (t.subtaskCount || 0) - 1),
                        };
                    }),
                );
            }

            if (action === "SUBTASK_UPDATED" && record.parentTaskId) {
                setLocalTaskDataMap(prev => ({ ...prev, [record.id]: { ...prev[record.id], ...record } }));
                const updatedSubtask = transformToGanttSubtasks([record]);
                setTasks((prev) =>
                    prev.map((t) => {
                        if (t.id !== record.parentTaskId) return t;
                        return {
                            ...t,
                            subtasks: t.subtasks?.map((s) =>
                                s.id === record.id ? { ...s, ...updatedSubtask[0] } : s,
                            ),
                        };
                    }),
                );
            }
        };

        window.addEventListener("realtime-sync-refresh", handleRealtimeSync);
        return () => window.removeEventListener("realtime-sync-refresh", handleRealtimeSync);
    }, [workspaceId, projectId]);


    // 🔑 Force GanttChart to reset its internal expansion state when filters change
    const filterKey = useMemo(() =>
        JSON.stringify({
            filters,
            searchQuery,
            workspaceId,
            projectId
        }),
        [filters, searchQuery, workspaceId, projectId]
    );

    const fetchTasks = async (isLoadMore = false): Promise<void> => {
        if (isLoadMore && (!hasMore || isLoadingMore)) return;

        const params = new URLSearchParams();
        params.append("w", workspaceId);
        params.append("p", projectId);
        params.append("vm", "gantt");
        params.append("hm", "parents"); // Only fetch root tasks
        params.append("sub", "false"); // 🚀 True lazy loading: exclude subtasks in root fetch
        params.append("l", "50"); // 🔋 Reverted to 50 for faster initial response

        if (isLoadMore && nextCursor) {
            params.append("c", JSON.stringify(nextCursor));
        }

        if (filters.status) params.append("s", filters.status);
        if (filters.assigneeId) params.append("a", filters.assigneeId);
        if (filters.tagId) params.append("t", filters.tagId);
        if (filters.dueDateFilter) params.append("dt", filters.dueDateFilter);
        if (filters.startDate) params.append("da", filters.startDate instanceof Date ? filters.startDate.toISOString() : filters.startDate);
        if (filters.endDate) params.append("db", filters.endDate instanceof Date ? filters.endDate.toISOString() : filters.endDate);
        if (searchQuery) params.append("q", searchQuery);

        const fetchKey = `gantt-fetch-${params.toString()}`;
        if (fetchingIdsRef.current.has(fetchKey)) return;
        fetchingIdsRef.current.add(fetchKey);

        if (isLoadMore) setIsLoadingMore(true);

        try {
            const res = await fetch(`/api/v1/tasks?${params.toString()}`);
            const json = await res.json();
            if (json.success) {
                const result = json.data;
                const newRawTasks = result.tasks || [];

                // For Gantt, we might need some date formatting logic or just use as is
                // We'll transform these into GanttTasks
                const newGanttTasks = transformToGanttTasks(newRawTasks);

                // Update local data map for all tasks that arrived
                setLocalTaskDataMap(prev => {
                    const next = { ...prev };
                    newRawTasks.forEach((t: any) => {
                        next[t.id] = t;
                        if (t.subTasks) t.subTasks.forEach((s: any) => next[s.id] = s);
                    });
                    return next;
                });

                setTasks(prev => {
                    if (!isLoadMore) return newGanttTasks;
                    const existingIds = new Set(prev.map(t => t.id));
                    const uniqueNew = newGanttTasks.filter(t => !existingIds.has(t.id));
                    return [...prev, ...uniqueNew];
                });
                setNextCursor(result.nextCursor);
                setHasMore(result.hasMore);
                lastFetchTimeRef.current = Date.now(); // Track last successful fetch
            }
        } catch (err) {
            console.error("Failed to fetch gantt tasks:", err);
            toast.error("Failed to load tasks");
        } finally {
            fetchingIdsRef.current.delete(fetchKey);
            if (isLoadMore) setIsLoadingMore(false);
        }
    };

    useEffect(() => {
        // 🚿 Clear subtasks and expanded tracking on every filter change
        setTasks(prev => prev.map(t => ({ ...t, subtasks: undefined })));
        expandedTaskIdsRef.current.clear();

        const timer = setTimeout(() => {
            startTransition(() => {
                fetchTasks(false);
            });
        }, 300);
        return () => clearTimeout(timer);
    }, [workspaceId, projectId, filters, searchQuery]);

    const lastFetchTimeRef = useRef(0);

    const handleLoadMore = () => {
        // 🛡️ Guard: Prevent overlapping fetches or too-frequent pagination triggers
        const now = Date.now();
        if (now - lastFetchTimeRef.current < 2000) return; // 2s cooldown for pagination

        startTransition(() => {
            fetchTasks(true);
        });
    };

    const handleRequestSubtasks = async (taskId: string) => {
        if (fetchingIdsRef.current.has(taskId)) return;

        // 🧠 Cache Strategy: Bypass cache if any filters are active
        const hasActiveFilters = !!(filters.status || filters.assigneeId || filters.tagId || searchQuery || filters.startDate || filters.endDate);

        // Removed manual caching to stay consistent with "Zero-Optimistic" architecture.

        fetchingIdsRef.current.add(taskId);
        setLoadingSubtasks(prev => new Set(prev).add(taskId));

        try {
            const params = new URLSearchParams();
            params.set("w", workspaceId);
            params.set("p", projectId);
            params.set("ids", taskId);
            params.set("vm", "gantt");
            params.set("ps", "30"); // 🚀 Matches List view initial expansion

            if (filters.status) params.append("s", JSON.stringify(filters.status));
            if (filters.assigneeId) params.append("a", JSON.stringify(filters.assigneeId));
            if (filters.tagId) params.append("t", JSON.stringify(filters.tagId));
            if (searchQuery) params.append("q", searchQuery);

            if (filters.startDate) {
                const da = filters.startDate instanceof Date ? filters.startDate.toISOString() : filters.startDate;
                params.append("da", da);
            }
            if (filters.endDate) {
                const db = filters.endDate instanceof Date ? filters.endDate.toISOString() : filters.endDate;
                params.append("db", db);
            }

            const fetchUrl = `/api/v1/tasks/expansion/batch?${params.toString()}`;
            const res = await fetch(fetchUrl);
            const json = await res.json();

            if (json.success && json.data?.length > 0) {
                const batchResult = json.data[0];
                const subTasks = batchResult.subTasks || [];

                // 🚀 Sync: Store raw subtask data for the sheet
                setLocalTaskDataMap(prev => {
                    const next = { ...prev };
                    subTasks.forEach((s: any) => { next[s.id] = s; });
                    return next;
                });

                const transformedSubtasks = transformToGanttSubtasks(subTasks);
                setTasks(prev => prev.map(t =>
                    t.id === taskId ? {
                        ...t,
                        subtasks: transformedSubtasks,
                        hasMoreSubtasks: batchResult.hasMore,
                        subtaskCursor: batchResult.nextCursor
                    } : t
                ));
            } else {
                setTasks(prev => prev.map(t =>
                    t.id === taskId ? { ...t, subtasks: [], hasMoreSubtasks: false } : t
                ));
            }
        } catch (err) {
            console.error("[Project Gantt] Expansion failed for:", taskId, err);
            setTasks(prev => prev.map(t =>
                t.id === taskId ? { ...t, subtasks: undefined } : t
            ));
        } finally {
            fetchingIdsRef.current.delete(taskId);
            setLoadingSubtasks(prev => {
                const next = new Set(prev);
                next.delete(taskId);
                return next;
            });
        }
    };

    /**
     * 🚀 NEW: handleRequestMoreSubtasks
     * Fetches the next page of subtasks for a specific parent task.
     */
    const handleRequestMoreSubtasks = async (taskId: string) => {
        const task = tasks.find(t => t.id === taskId);
        if (!task || !task.hasMoreSubtasks || fetchingSubtasksRef.current.has(taskId)) return;

        fetchingSubtasksRef.current.add(taskId);
        setLoadingSubtasks(prev => new Set(prev).add(taskId));

        try {
            const params = new URLSearchParams({
                w: workspaceId,
                p: projectId,
                vm: "gantt",
                pt: taskId,    // 🚀 Parent filter (List view pattern)
                l: "30",       // 🚀 Matches List view pagination
                sub: "false"
            });

            if (task.subtaskCursor) {
                params.set("c", JSON.stringify(task.subtaskCursor));
            }

            if (filters.status) params.append("s", JSON.stringify(filters.status));
            if (filters.assigneeId) params.append("a", JSON.stringify(filters.assigneeId));
            if (filters.tagId) params.append("t", JSON.stringify(filters.tagId));
            if (searchQuery) params.append("q", searchQuery);
            if (filters.startDate) params.set("da", new Date(filters.startDate).toISOString());
            if (filters.endDate) params.set("db", new Date(filters.endDate).toISOString());

            const res = await fetch(`/api/v1/tasks?${params.toString()}`);
            const json = await res.json();

            if (json.success && json.data) {
                const result = json.data;
                const rawSubtasks = result.tasks || [];

                // 🚀 Sync: Store raw subtask data for the sheet
                setLocalTaskDataMap(prev => {
                    const next = { ...prev };
                    rawSubtasks.forEach((s: any) => { next[s.id] = s; });
                    return next;
                });

                setTasks(prev => {
                    const next = [...prev];
                    const idx = next.findIndex(t => t.id === taskId);
                    if (idx !== -1) {
                        const currentSubtasks = next[idx].subtasks || [];
                        const newSubtasks = transformToGanttSubtasks(rawSubtasks);

                        // Deduplicate subtasks by ID
                        const existingIds = new Set(currentSubtasks.map(s => s.id));
                        const uniqueNew = newSubtasks.filter(s => !existingIds.has(s.id));

                        next[idx] = {
                            ...next[idx],
                            subtasks: [...currentSubtasks, ...uniqueNew],
                            hasMoreSubtasks: result.hasMore,
                            subtaskCursor: result.nextCursor
                        };
                    }
                    return next;
                });
            }
        } catch (err) {
            console.error("[Project Gantt] Load more subtasks failed:", err);
        } finally {
            fetchingSubtasksRef.current.delete(taskId);
            setLoadingSubtasks(prev => {
                const next = new Set(prev);
                next.delete(taskId);
                return next;
            });
        }
    };

    // Surgical update for subtasks (e.g. assignee change)
    const handleSubTaskUpdate = (subTaskId: string, updatedData: Partial<any>) => {
        setTasks(prevTasks => {
            return prevTasks.map(task => {
                // If the updated task is a parent task
                if (task.id === subTaskId) {
                    return { ...task, ...updatedData };
                }

                // If it's a subtask within a parent task
                if (task.subtasks) {
                    const hasSubtask = task.subtasks.find(s => s.id === subTaskId);
                    if (hasSubtask) {
                        return {
                            ...task,
                            subtasks: task.subtasks.map(s =>
                                s.id === subTaskId ? { ...s, ...updatedData } : s
                            )
                        };
                    }
                }
                return task;
            });
        });
    };

    const ganttTasks = tasks;

    // Transform full member objects for the toolbar dropdowns
    const toolbarMembers = members.map(m => ({
        id: m.userId,
        surname: m.user.surname || '',
    }));

    return (
        <div className="space-y-4">
            <GlobalFilterToolbar
                level="project"
                view="gantt"
                filters={filters}
                searchQuery={searchQuery}
                members={toolbarMembers as any}
                tags={tags}
                onFilterChange={handleFilterChange}
                onSearchChange={handleSearchChange}
                onClearAll={() => {
                    startTransition(() => {
                        clearFilters();
                    });
                }}
            />
            <div className="relative min-h-[400px]">
                {isPending && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center bg-background/50 backdrop-blur-sm transition-all duration-300">
                        <div className="flex flex-col items-center gap-2">
                            <Loader2 className="h-8 w-8 animate-spin text-primary" />
                            <span className="text-sm font-medium text-muted-foreground">Filtering...</span>
                        </div>
                    </div>
                )}
                <GanttChart
                    key={filterKey}
                    tasks={ganttTasks}
                    workspaceId={workspaceId}
                    projectId={projectId}
                    onSubtaskClick={handleOpenSubTaskSheetFromGantt}
                    onSubTaskUpdate={handleSubTaskUpdate}
                    projects={projects}
                    projectCounts={projectCounts}
                    members={members}
                    currentUser={currentUser}
                    permissions={permissions}
                    onLoadMore={handleLoadMore}
                    onRequestSubtasks={handleRequestSubtasks}
                    onRequestMoreSubtasks={handleRequestMoreSubtasks}
                    loadingSubtasks={loadingSubtasks}
                    isLoading={isLoadingMore || isPending}
                />
            </div>
        </div>
    );
}

"use client";

import { useEffect, useRef, useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Send, Loader2, ChevronDown, MessageSquare } from "lucide-react";
import { format, isSameDay } from "date-fns";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { cn } from "@/lib/utils";
import { apiClient } from "@/lib/api-client";
import { toast } from "sonner";

interface MessagesTabProps {
    taskId: string;
    workspaceId: string;
    projectId: string;
    comments: any[];
    setComments: (comments: any[] | ((prev: any[]) => any[])) => void;
    currentUserId: string | null;
    isLoading: boolean;
    hasMore: boolean;
    onLoadMore: () => void;
}

const ACCENT_GREEN = "bg-[#10b981] text-white dark:bg-[#059669]";
const TEXT_GREEN   = "text-[#059669] dark:text-[#10b981]";

export function MessagesTab({
    taskId, workspaceId, projectId,
    comments, setComments,
    currentUserId,
    isLoading, hasMore, onLoadMore,
}: MessagesTabProps) {
    const [message, setMessage]             = useState("");
    const [isSending, setIsSending]         = useState(false);
    const [showScrollBtn, setShowScrollBtn] = useState(false);

    const scrollRef         = useRef<HTMLDivElement>(null);
    const didInitialScroll  = useRef(false);   // Have we done the first snap-to-bottom?
    const isLoadingMore     = useRef(false);   // Guard against double load-more
    const hasScrolledDown   = useRef(false);   // User must visit the bottom before paginating

    /* ─── Helpers ─────────────────────────────────────────────────── */
    const scrollToBottom = (behavior: ScrollBehavior = "smooth") => {
        const el = scrollRef.current;
        if (el) el.scrollTo({ top: el.scrollHeight, behavior });
    };

    /* ─── Reset when task changes ─────────────────────────────────── */
    useEffect(() => {
        didInitialScroll.current = false;
        isLoadingMore.current    = false;
        hasScrolledDown.current  = false;
        setShowScrollBtn(false);
    }, [taskId]);

    /* ─── Snap to bottom on FIRST load of comments ────────────────── */
    // This fires when comments go from [] to having data (initial fetch done).
    // It does NOT fire for subsequent load-more fetches because
    // didInitialScroll is already true by then.
    useEffect(() => {
        if (isLoading) return;                    // still fetching, wait
        if (didInitialScroll.current) return;     // already did initial snap
        if (comments.length === 0) return;        // nothing to scroll to yet

        didInitialScroll.current = true;

        // One frame for DOM to paint, then snap
        requestAnimationFrame(() => {
            scrollToBottom("auto");
            // Mark that we've visited the bottom — enables pagination
            hasScrolledDown.current = true;
        });
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [comments.length, isLoading]);

    /* ─── Scroll handler ──────────────────────────────────────────── */
    const handleScroll = () => {
        const el = scrollRef.current;
        if (!el) return;

        const { scrollTop, scrollHeight, clientHeight } = el;

        // Show / hide "jump to bottom" button
        setShowScrollBtn(scrollHeight - scrollTop - clientHeight > 200);

        // Track that user has visited the bottom at least once
        if (scrollHeight - scrollTop - clientHeight < 100) {
            hasScrolledDown.current = true;
        }

        // Load older messages when approaching the top — but ONLY after
        // the user has scrolled down to the bottom at least once.
        // This prevents auto-triggering on short conversations.
        if (
            didInitialScroll.current &&
            hasScrolledDown.current &&
            scrollTop <= 80 &&
            hasMore &&
            !isLoading &&
            !isLoadingMore.current
        ) {
            isLoadingMore.current = true;
            const prevHeight = scrollHeight;

            onLoadMore();

            // Wait for React to fully re-render the new messages, then restore position
            requestAnimationFrame(() => {
                setTimeout(() => {
                    const nel = scrollRef.current;
                    if (nel) {
                        const newScrollHeight = nel.scrollHeight;
                        const addedHeight = newScrollHeight - prevHeight;
                        // Position at the junction between old and new messages
                        nel.scrollTop = addedHeight;
                    }
                    isLoadingMore.current = false;
                }, 350);
            });
        }
    };

    /* ─── Send ─────────────────────────────────────────────────────── */
    const handleSend = async (e?: React.FormEvent) => {
        e?.preventDefault();
        if (!message.trim() || isSending) return;

        try {
            setIsSending(true);
            const res = await apiClient.comments.createComment({
                taskId, workspaceId, projectId, content: message.trim(),
            });

            if (res.data) {
                const newMsg = {
                    ...res.data,
                    userId: currentUserId,
                    createdAt: new Date().toISOString(),
                };
                setComments(prev => [newMsg, ...prev]);   // prepend (newest-first in state)
                setMessage("");
                requestAnimationFrame(() => scrollToBottom());
            } else {
                toast.error(res.error?.message || "Failed to send message");
            }
        } catch {
            toast.error("Failed to send message");
        } finally {
            setIsSending(false);
        }
    };

    /* ─── Render: flip state (newest-first) → chronological (oldest first) ── */
    const msgs = [...comments].reverse();

    return (
        <div className="flex-1 flex flex-col bg-background relative overflow-hidden h-full">

            {/* Dot pattern */}
            <div className="absolute inset-0 opacity-[0.03] dark:opacity-[0.05] pointer-events-none chat-bg-dots" />

            {/* ── Scroll area ─────────────────────────────────────── */}
            <div
                ref={scrollRef}
                onScroll={handleScroll}
                className="flex-1 overflow-y-auto px-4 sm:px-6 z-10 scrollbar-chat"
            >
                {/* Loading older messages indicator (sticky at top) */}
                {isLoading && hasMore && (
                    <div className="flex justify-center py-3 sticky top-0 z-10">
                        <div className="bg-muted/60 backdrop-blur rounded-full px-3 py-1 flex items-center gap-2">
                            <Loader2 className="h-3.5 w-3.5 animate-spin text-muted-foreground" />
                            <span className="text-[10px] text-muted-foreground font-medium">
                                Loading older messages…
                            </span>
                        </div>
                    </div>
                )}

                {/* Initial loading state */}
                {isLoading && comments.length === 0 && (
                    <div className="flex justify-center items-center h-32">
                        <Loader2 className="h-5 w-5 animate-spin text-muted-foreground/30" />
                    </div>
                )}

                {/* Empty state */}
                {!isLoading && msgs.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-64 text-center opacity-40">
                        <MessageSquare className="h-10 w-10 mb-3" />
                        <p className="text-sm font-semibold">No messages yet</p>
                    </div>
                )}

                {/* ── Message list ──────────────────────────────────── */}
                <div className="flex flex-col py-6 gap-0">
                    {msgs.map((c, i) => {
                        const senderId    = c.userId || c.authorId;
                        const isMe        = senderId === currentUserId;
                        const author      = c.user || c.author?.workspaceMember?.user || c.author;
                        const date        = new Date(c.createdAt);
                        const prev        = msgs[i - 1];
                        const isFirstGrp  = !prev || (prev.userId || prev.authorId) !== senderId;
                        const isNewDay    = !prev || !isSameDay(date, new Date(prev.createdAt));

                        return (
                            <div key={c.id + i} className="flex flex-col">

                                {/* Date separator */}
                                {isNewDay && (
                                    <div className="flex justify-center my-5">
                                        <span className="bg-muted/50 backdrop-blur px-3 py-0.5 rounded-full text-[9px] font-bold text-muted-foreground uppercase tracking-widest border border-border/10">
                                            {format(date, "MMMM d, yyyy")}
                                        </span>
                                    </div>
                                )}

                                {/* Bubble row */}
                                <div className={cn(
                                    "flex w-full",
                                    isMe ? "justify-end" : "justify-start",
                                    isFirstGrp ? "mt-4" : "mt-0.5",
                                )}>
                                    <div className={cn(
                                        "flex max-w-[85%] sm:max-w-[75%] gap-2",
                                        isMe ? "flex-row-reverse" : "flex-row",
                                    )}>
                                        {/* Avatar */}
                                        {!isMe && isFirstGrp && (
                                            <Avatar className="h-7 w-7 mt-0.5 shrink-0 border border-border/30">
                                                <AvatarImage src={author?.image} />
                                                <AvatarFallback className="bg-muted text-[9px] font-bold">
                                                    {author?.name?.[0]}{author?.surname?.[0]}
                                                </AvatarFallback>
                                            </Avatar>
                                        )}
                                        {!isMe && !isFirstGrp && <div className="w-7 shrink-0" />}

                                        {/* Bubble */}
                                        <div className={cn(
                                            "px-3.5 py-1.5 rounded-[18px] shadow-sm",
                                            isMe
                                                ? `${ACCENT_GREEN} rounded-tr-none`
                                                : "bg-muted text-foreground rounded-tl-none border border-border/20",
                                        )}>
                                            {!isMe && isFirstGrp && (
                                                <span className={cn("block text-[10px] font-bold mb-0.5", TEXT_GREEN)}>
                                                    {author?.name} {author?.surname}
                                                </span>
                                            )}
                                            <div className="flex flex-wrap items-end gap-x-4 gap-y-0.5">
                                                <p className="text-[14px] leading-[19px] whitespace-pre-wrap break-words flex-1 min-w-[50px]">
                                                    {c.content}
                                                </p>
                                                <span className={cn(
                                                    "text-[8.5px] font-bold shrink-0 ml-auto opacity-60",
                                                    isMe ? "text-white" : "text-muted-foreground",
                                                )}>
                                                    {format(date, "h:mm a")}
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* ── Jump to bottom ────────────────────────────────────── */}
            {showScrollBtn && (
                <button
                    onClick={() => scrollToBottom()}
                    className="absolute bottom-24 right-5 z-20 w-9 h-9 rounded-full bg-background/90 backdrop-blur border border-border/50 flex items-center justify-center shadow-lg hover:bg-muted transition-all"
                >
                    <ChevronDown className="h-5 w-5" />
                </button>
            )}

            {/* ── Input ─────────────────────────────────────────────── */}
            <div className="shrink-0 p-4 bg-background/95 backdrop-blur border-t z-20">
                <form onSubmit={handleSend} className="flex gap-2 items-center">
                    <Input
                        value={message}
                        onChange={(e) => setMessage(e.target.value)}
                        placeholder="Type a message…"
                        disabled={isSending}
                        className="flex-1 bg-muted/40 border-none focus-visible:ring-1 focus-visible:ring-emerald-500/20 rounded-[14px] h-12 px-4 text-[14.5px] placeholder:text-muted-foreground/40"
                    />
                    <Button
                        type="submit"
                        size="icon"
                        disabled={!message.trim() || isSending}
                        className={cn(
                            "h-12 w-12 rounded-full shrink-0 shadow-md transition-all",
                            message.trim()
                                ? `${ACCENT_GREEN} hover:opacity-90`
                                : "bg-muted text-muted-foreground",
                        )}
                    >
                        {isSending
                            ? <Loader2 className="h-5 w-5 animate-spin" />
                            : <Send className="h-5 w-5" />
                        }
                    </Button>
                </form>
            </div>

            <style jsx global>{`
                .chat-bg-dots {
                    background-image: radial-gradient(circle at 1px 1px, currentColor 1px, transparent 0);
                    background-size: 22px 22px;
                }
                .scrollbar-chat::-webkit-scrollbar { width: 5px; }
                .scrollbar-chat::-webkit-scrollbar-thumb {
                    background: rgba(128,128,128,0.25);
                    border-radius: 10px;
                }
            `}</style>
        </div>
    );
}

"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import { useProjectLayout as useOptionalProjectLayout } from "../../project-layout-context";
import { SubtaskSheetHeader } from "./subtask-sheet-header";
import { SubtaskSheetNavBar } from "./subtask-sheet-navbar";
import { MessagesTab } from "./messages-tab";
import { ActivityTab } from "./activity-tab";
import { Tabs } from "@/components/ui/tabs";
import { apiClient } from "@/lib/api-client";
import type { SubTaskType } from "@/types/task";
import { toast } from "sonner";
import { useWorkspaceLayout } from "@/app/w/[workspaceId]/_components/workspace-layout-context";

interface SubTaskDetailsSheetProps {
    subTask: SubTaskType | null;
    isOpen: boolean;
    onClose: () => void;
    onSubTaskAssigned?: (subTaskId: string, updatedData: any) => void;
}

export function SubTaskDetailsSheet({
    subTask,
    isOpen,
    onClose,
    onSubTaskAssigned
}: SubTaskDetailsSheetProps) {
    // 🚀 Context Safety: GlobalSubTaskSheet might be used outside ProjectLayout
    let projectCtx: any = null;
    try { projectCtx = useOptionalProjectLayout(); } catch (e) { }

    const { data: workspaceData, workspaceId: workspaceIdFromContext } = useWorkspaceLayout();

    // Fallback to local state if project context is missing
    const [localMembers, setLocalMembers] = useState<any[]>([]);
    const [isLocalLoading, setIsLocalLoading] = useState(false);

    const workspaceId = projectCtx?.workspaceId || subTask?.workspaceId || workspaceIdFromContext;
    const projectId = projectCtx?.projectId || subTask?.projectId;
    const members = projectCtx?.projectMembers || localMembers;
    const tags = projectCtx?.workspaceTags || workspaceData?.tags || [];

    const permissions = projectCtx?.projectPermissions || {
        userId: workspaceData?.permissions?.userId,
        isWorkspaceAdmin: workspaceData?.permissions?.workspaceRole === 'ADMIN' || workspaceData?.permissions?.workspaceRole === 'OWNER',
        isProjectManager: false
    };

    const currentUserId = permissions.userId;
    const isAdmin = permissions.isWorkspaceAdmin;
    const isProjectManager = permissions.isProjectManager;

    const [activeTab, setActiveTab] = useState<"messages" | "review">("messages");
    const [comments, setComments] = useState<any[]>([]);
    const [activities, setActivities] = useState<any[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isLoadingActivity, setIsLoadingActivity] = useState(false);

    // Pagination states
    const [nextCommentsCursor, setNextCommentsCursor] = useState<string | null>(null);
    const [hasMoreComments, setHasMoreComments] = useState(true);
    const [nextActivitiesCursor, setNextActivitiesCursor] = useState<string | null>(null);
    const [hasMoreActivities, setHasMoreActivities] = useState(true);

    const [cachedData, setCachedData] = useState<Record<string, any>>({});

    const lastValidTask = useRef<SubTaskType | null>(null);
    if (subTask) {
        lastValidTask.current = subTask;
    }

    // Fetch members if context is missing
    useEffect(() => {
        if (!projectCtx && projectId && isOpen) {
            const fetchMembers = async () => {
                try {
                    setIsLocalLoading(true);
                    const membersList = await apiClient.projects.getMembers(projectId);
                    setLocalMembers(membersList || []);
                } catch (e) {
                    console.error("Failed to fetch local project members:", e);
                } finally {
                    setIsLocalLoading(false);
                }
            };
            fetchMembers();
        }
    }, [projectCtx, projectId, isOpen]);

    const loadComments = useCallback(async (isLoadMore = false) => {
        if (!subTask?.id || (isLoadMore && !hasMoreComments) || isLoading) return;

        try {
            setIsLoading(true);
            const limit = 10;
            const cursor = isLoadMore ? (nextCommentsCursor || undefined) : undefined;

            const res = await apiClient.comments.getComments(subTask.id, cursor, limit);

            if (res.data) {
                const newComments = res.data.items || [];
                console.log(`DEBUG [SubTaskDetailsSheet] Fetched ${newComments.length} comments. isLoadMore: ${isLoadMore}`);

                setComments(prev => {
                    const combined = isLoadMore ? [...prev, ...newComments] : newComments;
                    // De-duplicate by ID
                    const seen = new Set();
                    return combined.filter(c => {
                        if (seen.has(c.id)) return false;
                        seen.add(c.id);
                        return true;
                    });
                });
                setNextCommentsCursor(res.data.nextCursor || null);
                setHasMoreComments(!!res.data.nextCursor);

                if (!isLoadMore) {
                    setCachedData(prev => ({
                        ...prev,
                        [subTask.id]: {
                            ...prev[subTask.id],
                            comments: res.data
                        }
                    }));
                }
            }
        } catch (error) {
            console.error("Failed to load comments:", error);
        } finally {
            setIsLoading(false);
        }
    }, [subTask?.id, nextCommentsCursor, hasMoreComments, isLoading]);

    const loadActivities = useCallback(async (isLoadMore = false) => {
        if (!subTask?.id || (isLoadMore && !hasMoreActivities) || isLoadingActivity) return;

        try {
            setIsLoadingActivity(true);
            const limit = 10;
            const cursor = isLoadMore ? (nextActivitiesCursor || undefined) : undefined;

            const res = await apiClient.comments.getActivities(subTask.id, cursor, limit);

            if (res.data) {
                const newActivities = res.data.items || [];
                setActivities(prev => isLoadMore ? [...prev, ...newActivities] : newActivities);
                setNextActivitiesCursor(res.data.nextCursor || null);
                setHasMoreActivities(!!res.data.nextCursor);

                if (!isLoadMore) {
                    setCachedData(prev => ({
                        ...prev,
                        [subTask.id]: {
                            ...prev[subTask.id],
                            activities: res.data
                        }
                    }));
                }
            }
        } catch (error) {
            console.error("Failed to load activities:", error);
        } finally {
            setIsLoadingActivity(false);
        }
    }, [subTask?.id, nextActivitiesCursor, hasMoreActivities, isLoadingActivity]);

    // Initial load when subTask changes
    useEffect(() => {
        if (isOpen && subTask?.id) {
            const cached = cachedData[subTask.id];
            if (cached) {
                setComments(cached.comments?.items || []);
                setNextCommentsCursor(cached.comments?.nextCursor || null);
                setHasMoreComments(!!cached.comments?.nextCursor);

                setActivities(cached.activities?.items || []);
                setNextActivitiesCursor(cached.activities?.nextCursor || null);
                setHasMoreActivities(!!cached.activities?.nextCursor);
            } else {
                loadComments();
                loadActivities();
            }
        }
    }, [subTask?.id, isOpen]);

    const handleTabChange = (tab: "messages" | "review") => {
        setActiveTab(tab);
    };

    const handleSubTaskUpdated = useCallback(async (updatedData: any) => {
        if (!subTask?.id || !workspaceId || !projectId) return;
        try {
            const res = await apiClient.tasks.updateTask(subTask.id, workspaceId, projectId, updatedData);
            if (res.status === "success") {
                toast.success("Task updated successfully");
                if (projectCtx?.revalidate) projectCtx.revalidate();
            } else {
                toast.error(res.message || "Failed to update task");
            }
        } catch (error) {
            toast.error("Failed to update task");
        }
    }, [subTask?.id, workspaceId, projectId, projectCtx]);

    const task = isOpen ? subTask : lastValidTask.current;

    if (!task && isOpen) {
        return (
            <div className="flex-1 flex flex-col p-6 space-y-6">
                <div className="space-y-2">
                    <div className="h-8 w-1/3 bg-muted animate-pulse rounded-lg" />
                    <div className="h-4 w-1/4 bg-muted animate-pulse rounded-lg" />
                </div>
                <div className="space-y-4">
                    <div className="h-32 w-full bg-muted animate-pulse rounded-lg" />
                    <div className="h-32 w-full bg-muted animate-pulse rounded-lg" />
                    <div className="h-32 w-full bg-muted animate-pulse rounded-lg" />
                </div>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full overflow-hidden bg-background">
            {task ? (
                <>
                    <SubtaskSheetHeader
                        subTask={task as any}
                        currentUserId={currentUserId || ""}
                        members={members}
                        tags={tags}
                        isAdmin={isAdmin}
                        isProjectManager={isProjectManager}
                        onSubTaskUpdated={handleSubTaskUpdated}
                        onSubTaskAssigned={(memberObj) => {
                            const updatedData = {
                                assigneeId: memberObj.id
                            };
                            onSubTaskAssigned?.(task.id, updatedData);
                            handleSubTaskUpdated(updatedData);
                        }}
                    />

                    <div className="border-t flex-1 flex flex-col min-h-0">
                        <Tabs value={activeTab} onValueChange={(v) => handleTabChange(v as "messages" | "review")} className="flex flex-col h-full">
                            <SubtaskSheetNavBar
                                activeTab={activeTab}
                                onTabChange={handleTabChange}
                                messagesCount={comments.length}
                                activityCount={activities.length}
                            />

                            <div className="flex-1 flex flex-col min-h-0 relative">
                                <div className={activeTab === "messages" ? "flex-1 flex flex-col min-h-0" : "hidden"}>
                                    <MessagesTab
                                        taskId={task.id}
                                        workspaceId={workspaceId || ""}
                                        projectId={projectId || ""}
                                        comments={comments}
                                        setComments={setComments}
                                        currentUserId={currentUserId}
                                        isLoading={isLoading}
                                        hasMore={hasMoreComments}
                                        onLoadMore={() => loadComments(true)}
                                    />
                                </div>

                                <div className={activeTab === "review" ? "flex-1 flex flex-col min-h-0" : "hidden"}>
                                    <ActivityTab
                                        activities={activities}
                                        isLoadingActivity={isLoadingActivity}
                                        hasMore={hasMoreActivities}
                                        onLoadMore={() => loadActivities(true)}
                                    />
                                </div>
                            </div>
                        </Tabs>
                    </div>
                </>
            ) : null}
        </div>
    );
}

"use client";

import type { TaskByIdType } from "@/server/services/task/tasks.service";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Calendar, Tag, User, FileCheck } from "lucide-react";
import { cn, formatIST } from "@/lib/utils";
import { getStatusColors, getStatusLabel } from "@/lib/colors/status-colors";
import { memo, useState, useEffect } from "react";

import { InlineAssigneePicker } from "@/components/task/shared/inline-assignee-picker";
import { useRemainingDays } from "@/hooks/use-due-date";
import { useParams } from "next/navigation";
import { useWorkspaceLayout } from "@/app/w/[workspaceId]/_components/workspace-layout-context";

interface SubtaskSheetHeaderProps {
    subTask: TaskByIdType;
    currentUserId?: string | null;
    members?: any[];
    onSubTaskAssigned?: (memberObj: { id: string; name: string | null; surname: string | null }) => void;
    onSubTaskUpdated?: (updatedTask: Partial<TaskByIdType>) => void;
    isAdmin?: boolean;
    isProjectManager?: boolean;
    tags?: { id: string; name: string; }[];
}

export const SubtaskSheetHeader = memo(function SubtaskSheetHeader({
    subTask,
    currentUserId,
    members = [],
    onSubTaskAssigned,
    onSubTaskUpdated,
    isAdmin,
    isProjectManager,
    tags = []
}: SubtaskSheetHeaderProps) {
    const [isExpanded, setIsExpanded] = useState(false);
    const params = useParams();
    const { data: workspaceData } = useWorkspaceLayout();

    useEffect(() => {
        console.log("Subtask Sheet Data:", subTask);
    }, [subTask]);

    if (!subTask) return null;

    // Get project name from workspace layout context if not in subTask
    const projectSlug = params.slug as string;
    const currentProject = workspaceData.projects?.find((p: any) => p.slug === projectSlug);
    const projectName = currentProject?.name || subTask.project?.name;

    // Assignee calculation
    const assignee = (subTask.assignee as any)?.workspaceMember?.user || subTask.assignee;

    const { remainingDays, isOverdue, dueDate } = useRemainingDays(
        subTask.startDate,
        subTask.days,
        subTask.dueDate
    );

    return (
        <div className="px-4 sm:px-6 pt-6 pb-4 border-b flex-shrink-0">
            <div className="flex items-start justify-between">
                <div className="flex-1 min-w-0">
                    {/* Project & Parent Breadcrumb */}
                    {projectName && (
                        <div className="mb-2.5 flex items-center gap-2 overflow-hidden">
                            <Badge variant="secondary" className="bg-primary/10 text-primary border-none text-[10px] font-bold px-2 py-0.5 uppercase tracking-wider rounded-md shrink-0">
                                {projectName}
                            </Badge>
                            {subTask.parentTask && (
                                <div className="flex items-center gap-2 min-w-0">
                                    <span className="text-muted-foreground/40 text-[10px] font-bold">/</span>
                                    <span className="text-[10px] font-no text-muted-foreground/60 uppercase tracking-widest truncate">
                                        {subTask.parentTask.name}
                                    </span>
                                </div>
                            )}
                        </div>
                    )}

                    <h2 className="text-xl sm:text-2xl font-medium break-words leading-tight text-foreground">
                        {subTask.name}
                    </h2>

                </div>


            </div>

            {/* Full-width Description Section */}
            {subTask.description && (
                <div className="mt-2">
                    <p className={cn(
                        "text-sm text-muted-foreground leading-relaxed",
                        !isExpanded && "line-clamp-3"
                    )}>
                        {typeof subTask.description === 'string' ? subTask.description : JSON.stringify(subTask.description)}
                    </p>
                    {String(subTask.description).length > 150 && (
                        <button
                            onClick={() => setIsExpanded(!isExpanded)}
                            className="text-xs font-semibold text-primary hover:underline mt-1 focus:outline-none"
                        >
                            {isExpanded ? "Show Less" : "Show More"}
                        </button>
                    )}
                </div>
            )}

            {/* Details Section - Scrollable to prevent header bloat */}
            <ScrollArea className="mt-4 max-h-[400px] -mx-1 px-1">
                <div className="space-y-6">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-10 gap-y-4">
                        {/* Column 1 */}
                        <div className="space-y-4">
                            {/* Assignee */}
                            <div className="flex items-center justify-between group">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <User className="h-3.5 w-3.5" />
                                    <span className="text-[10px] font-bold uppercase tracking-tight">Assignee</span>
                                </div>
                                {assignee ? (
                                    <div className="flex items-center gap-1.5">
                                        <Avatar className="h-5 w-5 border border-background shadow-sm">
                                            <AvatarFallback className="text-[8px]">{assignee.surname?.[0]}</AvatarFallback>
                                        </Avatar>
                                        <span className="text-xs font-semibold">{assignee.surname || ""}</span>
                                    </div>
                                ) : (
                                    <InlineAssigneePicker
                                        subTask={subTask as any}
                                        members={members}
                                        projectId={subTask.projectId || ""}
                                        parentTaskId={subTask.parentTaskId || ""}
                                        canEdit={!!(isAdmin || isProjectManager || subTask.createdBy?.id === currentUserId || (subTask as any).createdById === currentUserId)}
                                        onAssigned={(_userId, member) => {
                                            onSubTaskAssigned?.({
                                                id: member.userId,
                                                name: member.user.name,
                                                surname: member.user.surname,
                                            });
                                        }}
                                    />
                                )}
                            </div>

                            {/* Status */}
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <FileCheck className="h-3.5 w-3.5" />
                                    <span className="text-[10px] font-bold uppercase tracking-tight">Status</span>
                                </div>
                                {subTask.status ? (
                                    <Badge
                                        variant="outline"
                                        className={cn(
                                            "text-[9px] font-black px-1.5 py-0 leading-none h-4 uppercase",
                                            getStatusColors(subTask.status).color,
                                            getStatusColors(subTask.status).bgColor,
                                            getStatusColors(subTask.status).borderColor
                                        )}
                                    >
                                        {getStatusLabel(subTask.status)}
                                    </Badge>
                                ) : (
                                    <span className="text-[10px] font-medium text-muted-foreground italic">None</span>
                                )}
                            </div>

                            {/* Tags */}
                            <div className="flex flex-col gap-1.5 pt-1 border-t border-dashed border-border/50">
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-2 text-muted-foreground">
                                        <Tag className="h-3.5 w-3.5" />
                                        <span className="text-[10px] font-bold uppercase tracking-tight">Tags</span>
                                    </div>
                                    <div className="flex flex-wrap gap-1 justify-end max-w-[120px]">
                                        {subTask.tags && subTask.tags.length > 0 ? (
                                            subTask.tags.slice(0, 2).map(t => (
                                                <Badge key={t.id} variant="secondary" className="rounded-md text-[8px] font-bold bg-primary/5 text-primary border-none px-1 h-3.5">
                                                    {t.name}
                                                </Badge>
                                            ))
                                        ) : (
                                            <span className="text-[10px] text-muted-foreground italic">None</span>
                                        )}
                                        {subTask.tags && subTask.tags.length > 2 && (
                                            <span className="text-[8px] font-bold text-muted-foreground">+{subTask.tags.length - 2}</span>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Column 2 */}
                        <div className="space-y-4">
                            {/* Start Date */}
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <Calendar className="h-3.5 w-3.5" />
                                    <span className="text-[10px] font-bold uppercase tracking-tight">Start Date</span>
                                </div>
                                <span className="text-xs font-bold">
                                    {subTask.startDate ? formatIST(subTask.startDate, "dd MMM yy") : "--"}
                                </span>
                            </div>

                            {/* Due Date */}
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    <Calendar className="h-3.5 w-3.5" />
                                    <span className="text-[10px] font-bold uppercase tracking-tight">Due Date</span>
                                </div>
                                <span className="text-xs font-bold">
                                    {dueDate ? formatIST(dueDate, "dd MMM yy") : "--"}
                                </span>
                            </div>

                            {/* Delayed By */}
                            {isOverdue && (
                                <div className="flex items-center justify-between pt-1 border-t border-dashed border-destructive/20">
                                    <div className="flex items-center gap-2 text-destructive">
                                        <Calendar className="h-3.5 w-3.5" />
                                        <span className="text-[10px] font-bold uppercase tracking-tight">Delayed</span>
                                    </div>
                                    <span className="text-xs font-black text-destructive animate-pulse">
                                        {Math.abs(remainingDays!)} Days
                                    </span>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </ScrollArea>
        </div>
    );
});

"use client";

import slugify from "slugify";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { useTransition, useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { tryCatch } from "@/hooks/try-catch";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { useConfetti } from "@/hooks/use-confetti";
import { useWorkspaceLayout } from "../../_components/workspace-layout-context";
import { Resolver, useForm, useWatch } from "react-hook-form";
import { Textarea } from "@/components/ui/textarea";
import { zodResolver } from "@hookform/resolvers/zod";
import { type WorkspaceMembersResult } from "@/types/workspace";

import { projectsClient } from "@/lib/api-client/projects";
import { projectSchema, ProjectSchemaType } from "@/lib/zodSchemas";
import { Badge } from "@/components/ui/badge";
import { Check, Loader2, Plus, PlusIcon, SparkleIcon } from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { generateRandomColor, getColorFromString } from "@/lib/colors/project-colors";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem } from "@/components/ui/command";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";

interface iAppProps {
    members: WorkspaceMembersResult["workspaceMembers"]
    workspaceId: string,
    isAdmin: boolean;
    canCreateProject?: boolean;
    userRole?: string; // Workspace role of current user
    currentUserId?: string; // Current user's ID
}

export const CreateProjectForm = ({ members, workspaceId, isAdmin, canCreateProject, userRole, currentUserId }: iAppProps) => {
    const [pending, startTransition] = useTransition();
    const router = useRouter();
    const { triggerConfetti } = useConfetti();
    const [mounted, setMounted] = useState(false);
    const [open, setOpen] = useState(false);

    useEffect(() => {
        setMounted(true);
    }, []);

    // Use explicit permission if provided, otherwise fallback to legacy isAdmin check
    const showCreateButton = canCreateProject ?? isAdmin;

    // Determine if user is MANAGER (auto-assigned as project manager)
    const isManager = userRole === "MANAGER";

    const { revalidate } = useWorkspaceLayout();

    const form = useForm<ProjectSchemaType>({
        resolver: zodResolver(projectSchema) as unknown as Resolver<ProjectSchemaType>,
        defaultValues: {
            name: "",
            description: "",
            slug: "",
            color: generateRandomColor(),
            address: "",
            directorName: "",
            companyName: "",
            registeredCompanyName: "",
            gstNumber: "",
            contactPerson: "",
            phoneNumber: "",
            workspaceId: workspaceId as string,
            // Auto-assign MANAGER as project lead
            projectManagerId: isManager ? (members?.find(m => m.userId === currentUserId)?.id || "") : "",
            memberAccess: [] as string[],
        },
    })

    const watchedName = useWatch({
        control: form.control,
        name: "name",
    });

    const watchedColor = useWatch({
        control: form.control,
        name: "color",
    });

    const watchedSlug = useWatch({
        control: form.control,
        name: "slug",
    });

    useEffect(() => {
        if (watchedName) {
            const autoColor = getColorFromString(watchedName);
            form.setValue("color", autoColor, { shouldDirty: true });
            const generatedSlug = slugify(watchedName, { lower: true, strict: true });
            form.setValue("slug", generatedSlug, { shouldDirty: true, shouldValidate: true });
        }
    }, [watchedName, form]);

    function onSubmit(data: ProjectSchemaType) {
        if (pending) return;
        startTransition(async () => {
            const { data: result, error } = await tryCatch(projectsClient.create(data));
            console.log("results", { result });

            if (error) {
                toast.error(error.message);
                console.error(error);
                return;
            }

            if (result.success) {
                toast.success(result.message || "Project created successfully!");
                triggerConfetti();
                form.reset();
                setOpen(false); // Close the dialog

                // Redirect to the newly created project's page
                if (result.data?.slug) {
                    router.push(`/w/${workspaceId}/p/${result.data.slug}`);
                } else {
                    router.push(`/w/${workspaceId}`);
                }
            } else {
                toast.error(result.message);
            }
        });
    }

    // --- Updated CreateProjectDialog.tsx (JSX / TSX) ---
    return (
        <>
            <Dialog open={open} onOpenChange={setOpen}>
                {showCreateButton && mounted && (
                    <DialogTrigger asChild>
                        <button className="cursor-pointer">
                            <Plus size={16} />
                        </button>
                    </DialogTrigger>
                )}
                {/* Make the dialog content scrollable when form grows */}
                <DialogContent className="max-h-[98vh] w-[min(900px,95vw)] overflow-hidden">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-3">
                            Create New Project
                            <div
                                className="h-5 w-5 rounded-full border shadow-sm transition-colors"
                                style={{ backgroundColor: watchedColor || "#000000" }}
                            />
                        </DialogTitle>
                    </DialogHeader>

                    {/* The scrollable area. Keeps header/footer sticky if you want:
                        - header is above already; if you want sticky footer, wrap form and footer separately. */}
                    <div className="mt-4 overflow-y-auto px-2 py-1 max-h-[70vh] thin-scrollbar">
                        <Form {...form}>
                            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-5">
                                <FormField
                                    control={form.control}
                                    name="name"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Project Name</FormLabel>
                                            <FormControl>
                                                <Input placeholder="Enter project name" {...field} />
                                            </FormControl>
                                            <input type="hidden" {...form.register("color")} />
                                            <input type="hidden" {...form.register("slug")} />
                                            {watchedSlug && (
                                                <p className="text-[10px] text-muted-foreground mt-1 ml-1">
                                                    Slug: <span className="font-mono">{watchedSlug}</span>
                                                </p>
                                            )}
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />

                                {/* Description */}
                                <FormField
                                    control={form.control}
                                    name="description"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Description</FormLabel>
                                            <FormControl>
                                                <Textarea
                                                    {...field}
                                                    placeholder="Project description"
                                                    className="resize-none"
                                                    rows={4}
                                                />
                                            </FormControl>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />

                                {/* two-column block */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <FormField
                                        control={form.control}
                                        name="companyName"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Company Name</FormLabel>
                                                <FormControl>
                                                    <Input placeholder="e.g. Google" {...field} />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="registeredCompanyName"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Registered Company Name</FormLabel>
                                                <FormControl>
                                                    <Input placeholder="Registered company name" {...field} />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="directorName"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Director Name</FormLabel>
                                                <FormControl>
                                                    <Input placeholder="eg: John Doe (MD)" {...field} />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="address"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Address</FormLabel>
                                                <FormControl>
                                                    <Input placeholder="eg:#123, Street name" {...field} />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />
                                </div>
                                <FormField
                                    control={form.control}
                                    name="gstNumber"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>GST Number</FormLabel>
                                            <FormControl>
                                                <Input
                                                    {...field}
                                                    placeholder="12ABCDE3456F7Z8"
                                                    inputMode="text"
                                                    maxLength={15}
                                                />
                                            </FormControl>
                                            <FormDescription className="text-xs text-muted-foreground">
                                                {/* GST is usually 15 characters — alphanumeric. (Add validation in schema) */}
                                            </FormDescription>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />

                                {/* contact details */}
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <FormField
                                        control={form.control}
                                        name="contactPerson"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Contact Person Name</FormLabel>
                                                <FormControl>
                                                    <Input placeholder="e.g. John Doe" {...field} type="text" />
                                                </FormControl>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />

                                    <FormField
                                        control={form.control}
                                        name="phoneNumber"
                                        render={({ field }) => (
                                            <FormItem>
                                                <FormLabel>Phone Number</FormLabel>
                                                <FormControl>
                                                    <Input
                                                        placeholder="e.g. +91 98765 43210"
                                                        {...field}
                                                        type="tel"
                                                        inputMode="tel"
                                                    />
                                                </FormControl>
                                                <FormDescription className="text-xs text-muted-foreground">
                                                    {/* Include country code. (Validate with pattern or phone library.) */}
                                                </FormDescription>
                                                <FormMessage />
                                            </FormItem>
                                        )}
                                    />
                                </div>

                                <FormField
                                    control={form.control}
                                    name="projectManagerId"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Project Manager</FormLabel>
                                            <FormDescription className="text-xs text-muted-foreground mb-2">
                                                {isManager
                                                    ? "As a workspace manager, you will be automatically assigned as the project manager."
                                                    : "Select a project manager who will have full project access. (Managers only)"
                                                }
                                            </FormDescription>
                                            <div className="space-y-2">
                                                {isManager ? (
                                                    // For MANAGER: Show non-editable field with their name
                                                    <Input
                                                        value={(() => {
                                                            const currentMember = members?.find((m) => m.userId === currentUserId);
                                                            return currentMember?.surname || "You";
                                                        })()}
                                                        disabled
                                                        className="bg-muted cursor-not-allowed"
                                                    />
                                                ) : (
                                                    // For OWNER/ADMIN: Show dropdown to select exactly one project manager
                                                    <Popover>
                                                        <PopoverTrigger asChild>
                                                            <Button variant="outline" className="w-full justify-between font-normal h-auto min-h-[40px] py-2">
                                                                <div className="flex flex-wrap gap-1">
                                                                    {field.value ? (
                                                                        (() => {
                                                                            const m = members?.find((m) => m.id === field.value);
                                                                            return (
                                                                                <Badge variant="secondary" className="px-1 font-normal">
                                                                                    {m?.surname || "Unknown"}
                                                                                </Badge>
                                                                            );
                                                                        })()
                                                                    ) : (
                                                                        <span className="text-muted-foreground">Select project manager</span>
                                                                    )}
                                                                </div>
                                                            </Button>
                                                        </PopoverTrigger>

                                                        <PopoverContent className="p-0 w-64" align="start">
                                                            <Command>
                                                                <CommandInput placeholder="Search managers…" />
                                                                <CommandEmpty>No workspace managers found.</CommandEmpty>

                                                                <CommandGroup className="max-h-64 overflow-y-auto">
                                                                    {members?.filter(m => m.workspaceRole === "MANAGER").map((member) => {
                                                                        const userName = member.surname || "Unknown Member";
                                                                        const isSelected = field.value === member.id;

                                                                        return (
                                                                            <CommandItem
                                                                                key={member.id}
                                                                                onSelect={() => {
                                                                                    field.onChange(isSelected ? "" : member.id);
                                                                                }}
                                                                            >
                                                                                <div className={cn(
                                                                                    "mr-2 flex h-4 w-4 items-center justify-center rounded-sm border border-primary",
                                                                                    isSelected ? "bg-primary text-primary-foreground" : "opacity-50 [&_svg]:invisible"
                                                                                )}>
                                                                                    <Check className="h-4 w-4" />
                                                                                </div>
                                                                                {userName}
                                                                            </CommandItem>
                                                                        );
                                                                    })}
                                                                </CommandGroup>
                                                            </Command>
                                                        </PopoverContent>
                                                    </Popover>
                                                )}
                                            </div>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />

                                <div className="flex justify-end items-center gap-4 pt-2 mb-2">
                                    <Button type="submit" disabled={pending}>
                                        {pending ? (
                                            <>
                                                Creating...
                                                <Loader2 className="ml-1 h-4 w-4 animate-spin" />
                                            </>
                                        ) : (
                                            <>
                                                Create Project
                                                <PlusIcon className="ml-1" size={16} />
                                            </>
                                        )}
                                    </Button>
                                </div>
                            </form>
                        </Form>
                    </div>
                </DialogContent>
            </Dialog>
        </>
    );
};

"use client";

import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { formatIST } from "@/lib/utils";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { useEffect, useState, useTransition } from "react";
import { Check, ChevronsUpDown } from "lucide-react";
import { DailyReportFormType } from "@/lib/zodSchemas";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { apiClient } from "@/lib/api-client";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";

interface Props {
    workspaceId: string;
    isOpen: boolean;
    onClose: () => void;
    onSubmitted?: () => void;
}

export function DailyReportModal({ workspaceId, isOpen, onClose, onSubmitted }: Props) {
    const [isPending, startTransition] = useTransition();

    const [entries, setEntries] = useState<DailyReportFormType["entries"]>([{ taskId: "", description: "" }]);
    const [suggestedTasks, setSuggestedTasks] = useState<any[]>([]);
    const [openPopoverIndex, setOpenPopoverIndex] = useState<number | null>(null);

    useEffect(() => {
        if (isOpen) {
            fetchData();
        }
    }, [isOpen, workspaceId]);

    const fetchData = async () => {
        try {
            const response = await apiClient.reports.getFormData(workspaceId);
            if (response.status === "success") {
                setSuggestedTasks(response.data.suggestedTasks || []);
            }
        } catch (error) {
            console.error("Failed to load suggested tasks", error);
        }
    };

    const updateEntry = (index: number, field: keyof DailyReportFormType["entries"][0], value: any) => {
        setEntries((prev) => {
            const newEntries = [...prev];
            newEntries[index] = { ...newEntries[index], [field]: value };
            return newEntries;
        });
    };

    const handleSubmit = () => {
        for (const entry of entries) {
            if (!entry.taskId) {
                toast.error("Please select a task (or 'Other Work') for all entries.");
                return;
            }
            if (!entry.description || entry.description.trim().length < 15) {
                toast.error("Descriptions must be at least 15 characters long.");
                return;
            }
        }

        startTransition(async () => {
            try {
                const response = await apiClient.reports.submitReport({
                    workspaceId,
                    entries,
                    date: formatIST(new Date(), "d MMM yyyy")
                });
                
                if (response.status === "error") {
                    throw new Error(response.message || "Failed to submit report");
                }
                
                toast.success("Daily report submitted successfully!");
                onSubmitted?.();
                onClose();
            } catch (error: any) {
                toast.error(error.message || "Failed to submit report");
            }
        });
    };

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="sm:max-w-[700px] max-h-[85vh] overflow-y-auto">
                <DialogHeader>
                    <DialogTitle>Daily Work Report</DialogTitle>
                    <DialogDescription>
                        Log the tasks you worked on today. Submitting is required to avoid being marked absent.
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-6 py-4">
                    {entries.map((entry, index) => {
                        const isOther = entry.taskId === "other";

                        return (
                            <div key={index} className="flex gap-4 p-4 border rounded-xl bg-card shadow-sm border-border/50 relative">
                                <div className="flex-1 space-y-4 pt-2">
                                    <div className="space-y-2 max-w-[calc(100%-2rem)]">
                                        <Label>Task / Work Type <span className="text-destructive">*</span></Label>
                                        <Popover
                                            open={openPopoverIndex === index}
                                            onOpenChange={(open) => setOpenPopoverIndex(open ? index : null)}
                                        >
                                            <PopoverTrigger asChild>
                                                <Button
                                                    variant="outline"
                                                    role="combobox"
                                                    aria-expanded={openPopoverIndex === index}
                                                    className="w-full justify-between"
                                                >
                                                    {entry.taskId
                                                        ? entry.taskId === "other"
                                                            ? "Other Work (No explicit task)"
                                                            : (() => {
                                                                const t = suggestedTasks.find((t) => t.id === entry.taskId);
                                                                if (!t) return "Select a task or 'Other Work'...";
                                                                const taskLabel = t.parentTask ? `${t.parentTask.name} / ${t.name}` : t.name;
                                                                return (
                                                                    <div className="flex items-center gap-2 truncate">
                                                                        <div
                                                                            className="w-2 h-2 rounded-full shrink-0"
                                                                            style={{ backgroundColor: t.project?.color || "#ccc" }}
                                                                        />
                                                                        <span className="truncate">{taskLabel}</span>
                                                                    </div>
                                                                );
                                                            })()
                                                        : "Select a task or 'Other Work'..."}
                                                    <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                                                </Button>
                                            </PopoverTrigger>
                                            <PopoverContent className="w-[--radix-popover-trigger-width] p-0" align="start">
                                                <Command filter={(value, search) => {
                                                    if (value === "other_work_no_explicit_task") return 1;
                                                    return value.toLowerCase().includes(search.toLowerCase()) ? 1 : 0;
                                                }}>
                                                    <CommandInput placeholder="Search tasks and subtasks..." />
                                                    <CommandList>
                                                        <CommandEmpty className="p-2 text-center text-sm text-muted-foreground">
                                                            No matching tasks. Try "Other Work".
                                                        </CommandEmpty>
                                                        <CommandGroup>
                                                            {suggestedTasks.map((t) => (
                                                                <CommandItem
                                                                    key={t.id}
                                                                    value={`${t.project?.name || ""} ${t.parentTask?.name || ""} ${t.name}`}
                                                                    onSelect={() => {
                                                                        updateEntry(index, "taskId", t.id);
                                                                        setOpenPopoverIndex(null);
                                                                    }}
                                                                >
                                                                    <Check
                                                                        className={cn(
                                                                            "mr-3 h-4 w-4 flex-shrink-0",
                                                                            entry.taskId === t.id ? "opacity-100" : "opacity-0"
                                                                        )}
                                                                    />
                                                                    <div className="flex flex-col truncate">
                                                                        <div className="flex items-center gap-2">
                                                                            <div
                                                                                className="w-1.5 h-1.5 rounded-full shrink-0"
                                                                                style={{ backgroundColor: t.project?.color || "#ccc" }}
                                                                            />
                                                                            <span className="font-medium text-[10px] text-muted-foreground uppercase tracking-tight">
                                                                                {t.project?.name}
                                                                            </span>
                                                                        </div>
                                                                        <span className="truncate">{t.name}</span>
                                                                        {t.parentTask && (
                                                                            <span className="text-[10px] text-muted-foreground truncate italic">
                                                                                {t.parentTask.name}
                                                                            </span>
                                                                        )}
                                                                    </div>
                                                                </CommandItem>
                                                            ))}
                                                        </CommandGroup>
                                                        <CommandGroup>
                                                            <CommandItem
                                                                value="other_work_no_explicit_task"
                                                                onSelect={() => {
                                                                    updateEntry(index, "taskId", "other");
                                                                    setOpenPopoverIndex(null);
                                                                }}
                                                            >
                                                                <Check
                                                                    className={cn(
                                                                        "mr-3 h-4 w-4 flex-shrink-0",
                                                                        entry.taskId === "other" ? "opacity-100" : "opacity-0"
                                                                    )}
                                                                />
                                                                <span className="font-semibold text-primary">Other Work</span>
                                                            </CommandItem>
                                                        </CommandGroup>
                                                    </CommandList>
                                                </Command>
                                            </PopoverContent>
                                        </Popover>
                                    </div>

                                    <div className="space-y-2">
                                        <Label>Description <span className="text-destructive">*</span></Label>
                                        <Textarea
                                            placeholder="What did you achieve today? (min 15 chars)"
                                            value={entry.description || ""}
                                            onChange={(e) => updateEntry(index, "description", e.target.value)}
                                            className="resize-none"
                                            rows={2}
                                        />
                                    </div>
                                </div>
                            </div>
                        );
                    })}
                </div>

                <DialogFooter className="mt-6 border-t pt-4">
                    <Button variant="outline" onClick={onClose} disabled={isPending}>
                        Cancel
                    </Button>
                    <Button
                        onClick={handleSubmit}
                        disabled={isPending || entries.length === 0}
                    >
                        {isPending ? "Submitting..." : "Submit Report"}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog >
    );
}

"use client";

import React, { useMemo, useState, useEffect, useCallback } from "react";
import { formatIST } from "@/lib/utils";
import { DataTable } from "@/components/data-table/data-table";
import { ColumnDef } from "@tanstack/react-table";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from "@/components/ui/command";
import { ReportDetailModal } from "./report-detail-sheet";
import { Loader2, CalendarIcon, UserIcon, X, ChevronDown, Clock, Search, ChevronRight, ChevronsUpDown, ChevronsDownUp } from "lucide-react";
import { apiClient } from "@/lib/api-client";
import { useWorkspaceMemberStore, useRealtimeMemberSync } from "@/lib/store/workspace-member-store";

interface Props {
    initialData: any[];
    workspaceId: string;
    initialDate?: string;
    initialUserId?: string;
    isAdmin: boolean;
    currentUserId: string;
}

export function ReportsTable({ initialData, workspaceId, initialDate, initialUserId, isAdmin, currentUserId }: Props) {
    const router = useRouter();
    const pathname = usePathname();
    const searchParams = useSearchParams();
    const [data, setData] = useState(initialData);
    const [isLoadingMore, setIsLoadingMore] = useState(false);
    const [hasMore, setHasMore] = useState(initialData.length >= 30);
    const [skip, setSkip] = useState(30);
    const [selectedReport, setSelectedReport] = useState<any>(null);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");
    const [expandedDates, setExpandedDates] = useState<Record<string, boolean>>({});
    const [expandedReports, setExpandedReports] = useState<Record<string, boolean>>({});

    const { membersByWorkspace, fetchMembers, isLoading: storeLoading } = useWorkspaceMemberStore();
    const members = membersByWorkspace[workspaceId] || [];
    const isMembersLoading = storeLoading[workspaceId] ?? true;

    // Subscribe to real-time updates for this workspace
    useRealtimeMemberSync(workspaceId);

    useEffect(() => {
        fetchMembers(workspaceId);
    }, [workspaceId, fetchMembers]);

    // Sync with initialData change (when server-side searchParams change)
    useEffect(() => {
        setData(initialData);
        setSkip(30);
        setHasMore(initialData.length >= 30);
    }, [initialData]);

    const selectedMember = useMemo(() => {
        return members.find(m => m.userId === initialUserId);
    }, [members, initialUserId]);

    const toggleDate = (dateStr: string) => {
        setExpandedDates(prev => ({ ...prev, [dateStr]: !prev[dateStr] }));
    };

    const toggleReport = (reportId: string) => {
        setExpandedReports(prev => ({ ...prev, [reportId]: !prev[reportId] }));
    };

    const populatedData = useMemo(() => {
        const dateGroups: Record<string, any[]> = {};

        // 1. Group existing data by date
        data.forEach(report => {
            let dateStr = "No Date";
            if (report.date) {
                dateStr = typeof report.date === "string"
                    ? report.date.split("T")[0]
                    : formatIST(report.date);
            }
            if (!dateGroups[dateStr]) dateGroups[dateStr] = [];
            dateGroups[dateStr].push(report);
        });

        // 2. Identify all dates to show
        const datesToShow = Array.from(new Set([
            ...Object.keys(dateGroups),
            ...(initialDate ? [initialDate] : [])
        ])).sort((a, b) => b.localeCompare(a));

        const result: Record<string, any[]> = {};

        // 3. For each date, create a fully populated list
        datesToShow.forEach(dateStr => {
            const reportsForDate = dateGroups[dateStr] || [];
            const userReportMap = new Map();
            reportsForDate.forEach(r => {
                const key = r.userId || r.user?.id || r.user?.email || r.reportId;
                if (key && !userReportMap.has(key)) userReportMap.set(key, r);
            });

            const membersToConsider = isAdmin
                ? (initialUserId ? members.filter(m => m.userId === initialUserId) : members)
                : members.filter(m => m.userId === currentUserId);

            result[dateStr] = membersToConsider.map(member => {
                const existing = userReportMap.get(member.userId) ||
                    (member.id ? userReportMap.get(member.id) : null) ||
                    (member.email ? userReportMap.get(member.email) : null);

                return existing || {
                    id: `virtual-${dateStr}-${member.id}`,
                    workspaceId,
                    userId: member.id,
                    user: member,
                    status: "NOT_SUBMITTED",
                    submittedAt: null,
                    date: dateStr,
                    entries: [],
                    description: "Not yet submitted."
                };
            });
        });
        return result;
    }, [data, members, isAdmin, initialUserId, currentUserId, initialDate, workspaceId]);

    const toggleAll = useCallback(() => {
        const anyExpanded = Object.values(expandedDates).some(v => v);

        if (anyExpanded) {
            setExpandedDates({});
            setExpandedReports({});
        } else {
            const dateKeys: Record<string, boolean> = {};
            const reportKeys: Record<string, boolean> = {};

            Object.entries(populatedData).forEach(([dateStr, reports]) => {
                // Only toggle if they would be visible (matching current search)
                const lowSearch = searchQuery.toLowerCase();
                const filtered = !searchQuery ? reports : reports.filter(item => {
                    const user = item.user;
                    const userName = `${user?.name || ""} ${user?.surname || ""} ${user?.email || ""}`.toLowerCase();
                    const entries = item.entries || [];
                    const taskMatch = entries.some((e: any) =>
                        (e.task?.name?.toLowerCase() || "").includes(lowSearch) ||
                        (e.task?.taskSlug?.toLowerCase() || "").includes(lowSearch) ||
                        (e.description?.toLowerCase() || "").includes(lowSearch)
                    );
                    const reportDescMatch = (item.description?.toLowerCase() || "").includes(lowSearch);
                    return userName.includes(lowSearch) || taskMatch || reportDescMatch;
                });

                if (filtered.length > 0) {
                    dateKeys[dateStr] = true;
                    filtered.forEach(r => {
                        reportKeys[r.id] = true;
                    });
                }
            });

            setExpandedDates(dateKeys);
            setExpandedReports(reportKeys);
        }
    }, [populatedData, expandedDates, searchQuery]);

    const updateFilters = useCallback((updates: Record<string, string | undefined>) => {
        const params = new URLSearchParams(searchParams.toString());
        Object.entries(updates).forEach(([key, value]) => {
            if (value) {
                params.set(key, value);
            } else {
                params.delete(key);
            }
        });
        router.push(`${pathname}?${params.toString()}`);
    }, [pathname, router, searchParams]);

    const loadMore = useCallback(async () => {
        if (isLoadingMore || !hasMore) return;

        setIsLoadingMore(true);
        try {
            const response = await apiClient.reports.getReports({
                workspaceId,
                date: initialDate,
                userId: initialUserId,
                skip: skip,
                take: 30
            });

            if (response.status === "error" || !response.data || response.data.length === 0) {
                setHasMore(false);
            } else {
                setData((prev: any[]) => [...prev, ...response.data]);
                setSkip((prev: number) => prev + 30);
            }
        } catch (error) {
            console.error("Failed to load more reports:", error);
        } finally {
            setIsLoadingMore(false);
        }
    }, [workspaceId, initialDate, initialUserId, skip, isLoadingMore, hasMore]);

    // Infinite scroll observer
    const observerRef = React.useRef<HTMLDivElement>(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                if (entries[0].isIntersecting && hasMore && !isLoadingMore) {
                    loadMore();
                }
            },
            { threshold: 0.1 }
        );

        if (observerRef.current) {
            observer.observe(observerRef.current);
        }

        return () => observer.disconnect();
    }, [loadMore, hasMore, isLoadingMore]);

    const processedRows = useMemo(() => {
        const rows: any[] = [];

        // Sort dates desc
        const sortedDateKeys = Object.keys(populatedData).sort((a, b) => b.localeCompare(a));
        const lowSearch = searchQuery.toLowerCase();

        sortedDateKeys.forEach(dateStr => {
            let reports = populatedData[dateStr];

            // Apply search filter
            if (searchQuery) {
                reports = reports.filter(item => {
                    const user = item.user;
                    const userName = `${user?.name || ""} ${user?.surname || ""} ${user?.email || ""}`.toLowerCase();
                    const entries = item.entries || [];
                    const taskMatch = entries.some((e: any) =>
                        (e.task?.name?.toLowerCase() || "").includes(lowSearch) ||
                        (e.task?.taskSlug?.toLowerCase() || "").includes(lowSearch) ||
                        (e.description?.toLowerCase() || "").includes(lowSearch)
                    );
                    const reportDescMatch = (item.description?.toLowerCase() || "").includes(lowSearch);
                    return userName.includes(lowSearch) || taskMatch || reportDescMatch;
                });
            }

            if (reports.length === 0) return;

            // Build hierarchy rows
            rows.push({
                id: `d-${dateStr}`,
                type: "date",
                date: dateStr,
                count: reports.length,
                level: 0
            });

            if (expandedDates[dateStr]) {
                const sortedReports = [...reports].sort((a, b) => {
                    const nameA = a.user?.surname || "";
                    const nameB = b.user?.surname || "";
                    return nameA.localeCompare(nameB);
                });

                sortedReports.forEach(report => {
                    rows.push({
                        id: `r-${report.id}`,
                        type: "user",
                        user: report.user,
                        report,
                        level: 1
                    });

                    if (expandedReports[report.id]) {
                        const entries = report.entries || [];
                        if (entries.length === 0) {
                            rows.push({
                                id: `empty-${report.id}`,
                                type: "entry",
                                entry: null,
                                report,
                                description: report.status === "ABSENT"
                                    ? "No report submitted (Absent)."
                                    : (report.status === "NOT_SUBMITTED"
                                        ? "Activity pending: No work logs recorded for this day yet."
                                        : "Empty report: Submitted without logs."),
                                level: 2
                            });
                        } else {
                            entries.forEach((entry: any) => {
                                rows.push({
                                    id: `e-${entry.id}`,
                                    type: "entry",
                                    entry,
                                    report,
                                    level: 2
                                });
                            });
                        }
                    }
                });
            }
        });

        return rows;
    }, [populatedData, expandedDates, expandedReports, searchQuery]);

    const reportColumns = useMemo<ColumnDef<any>[]>(() => [
        {
            accessorKey: "hierarchy",
            header: () => {
                const anyExpanded = Object.values(expandedDates).some(v => v);
                return (
                    <div className="flex items-center gap-1.5">
                        <Button
                            variant="ghost"
                            size="icon"
                            className="h-6 w-6 p-0 hover:bg-muted/60 text-muted-foreground hover:text-foreground shrink-0"
                            onClick={(e) => {
                                e.stopPropagation();
                                toggleAll();
                            }}
                            title={anyExpanded ? "Collapse All" : "Expand All"}
                        >
                            {anyExpanded ? <ChevronsDownUp className="h-3.5 w-3.5" /> : <ChevronsUpDown className="h-3.5 w-3.5" />}
                        </Button>
                        <span className="font-semibold text-xs tracking-tight">Date / Assignee</span>
                    </div>
                );
            },
            meta: { className: "[&_td]:align-top text-left" } as any,
            cell: ({ row }) => {
                const data = row.original;

                if (data.type === "date") {
                    const isExpanded = !!expandedDates[data.date];
                    return (
                        <div className="flex items-center gap-2 pb-1">
                            <Button
                                variant="ghost"
                                size="icon"
                                className="h-4 w-4 p-0 shrink-0"
                                onClick={(e) => {
                                    e.stopPropagation();
                                    toggleDate(data.date);
                                }}
                            >
                                {isExpanded ? <ChevronDown className="h-3 w-3" /> : <ChevronRight className="h-3 w-3" />}
                            </Button>
                            <CalendarIcon className="h-3.5 w-3.5 text-primary shrink-0" />
                            <span className="font-bold text-sm text-foreground">
                                {data.date !== "No Date" ? formatIST(new Date(`${data.date}T12:00:00`)) : "No Date"}
                            </span>
                            <Badge variant="secondary" className="px-1.5 py-0 h-4 text-[9px] font-bold opacity-70">
                                {data.count} reports
                            </Badge>
                        </div>
                    );
                }

                if (data.type === "user") {
                    const user = data.user;
                    const report = data.report;
                    const isExpanded = !!expandedReports[report.id];
                    return (
                        <div className="flex items-center gap-2 pb-1 ml-6">
                            <Button
                                variant="ghost"
                                size="icon"
                                className="h-4 w-4 p-0 shrink-0"
                                onClick={(e) => {
                                    e.stopPropagation();
                                    toggleReport(report.id);
                                }}
                            >
                                {isExpanded ? <ChevronDown className="h-3 w-3" /> : <ChevronRight className="h-3 w-3" />}
                            </Button>
                            <div className="w-6 h-6 rounded-full bg-secondary flex items-center justify-center overflow-hidden shrink-0 border shadow-sm">
                                {user?.image ? (
                                    <img src={user.image} alt={user.surname} className="w-full h-full object-cover" />
                                ) : (
                                    <span className="text-[10px] font-medium text-secondary-foreground">
                                        {user?.surname?.charAt(0) || "U"}
                                    </span>
                                )}
                            </div>
                            <span className="font-semibold text-xs truncate">{user?.surname}</span>
                            <Badge
                                variant={report.status === "ABSENT" ? "destructive" : "outline"}
                                className={cn(
                                    "text-[8px] h-3.5 px-1.5 shadow-none font-bold uppercase tracking-tighter ml-auto mr-2 shrink-0 transition-colors",
                                    report.status === "SUBMITTED" && "bg-emerald-500/10 text-emerald-600 border-emerald-500/20 hover:bg-emerald-500/20",
                                    report.status === "NOT_SUBMITTED" && "bg-amber-500/10 text-amber-600 border-amber-500/20 hover:bg-amber-500/20"
                                )}
                            >
                                {report.status.replace("_", " ")}
                            </Badge>
                        </div>
                    );
                }

                return null;
            }
        },
        {
            accessorKey: "tasks",
            header: "Task & Time",
            meta: { className: "w-[25%] border-l border-border/10 [&_td]:align-top text-left" } as any,
            cell: ({ row }) => {
                const data = row.original;
                if (data.type !== "entry") return null;

                const entry = data.entry;
                const submittedAt = data.report.submittedAt;

                if (!entry) {
                    return (
                        <div className="py-2 flex items-center gap-3 ml-12">
                            <span className="text-xs text-muted-foreground italic bg-muted/30 px-2 py-1 rounded-md border border-dashed">
                                {data.report.status === "ABSENT" ? "Absent" : "Other Work"}
                            </span>
                        </div>
                    );
                }

                return (
                    <div className="flex flex-col gap-1 pb-1 items-start justify-start min-h-[40px] ml-0">
                        <div className="flex items-center gap-2">
                            <div
                                className="w-2 h-2 rounded-full shrink-0 shadow-sm"
                                style={{ backgroundColor: entry.task?.project?.color || "#cbd5e1" }}
                            />
                            <span className="font-normal text-xs truncate leading-tight text-foreground/80">
                                {entry.task?.name || "Other Work"}
                            </span>
                        </div>
                        <div className="pl-4 flex items-center gap-2">
                            {submittedAt && (
                                <div className="flex items-center gap-1 text-[10px] text-muted-foreground/60 font-mono">
                                    <Clock className="h-2 w-2" />
                                    {formatIST(submittedAt, "h:mm a")}
                                </div>
                            )}
                        </div>
                    </div>
                );
            }
        },
        {
            accessorKey: "logs",
            header: "Work Log Descriptions",
            meta: { className: "w-[50%] border-l border-border/10 [&_td]:align-top text-left" } as any,
            cell: ({ row }) => {
                const data = row.original;
                if (data.type !== "entry") return null;

                const entry = data.entry;
                const description = entry ? entry.description : data.description;

                return (
                    <div className="pb-1 flex items-start min-h-[40px] ml-4">
                        <p className="text-sm text-card-foreground/90 font-normal leading-relaxed whitespace-pre-wrap">
                            {description || "-"}
                        </p>
                    </div>
                );
            }
        }
    ], [expandedDates, expandedReports, toggleAll]);

    return (
        <div className="flex flex-col h-[calc(100vh-210px)] min-h-[500px] gap-4">
            {/* Top Toolbar */}
            <div className="flex flex-wrap items-center gap-3 shrink-0">
                <div className="relative flex-1 max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Search assignees, tasks, or logs..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="pl-9 h-9 border-muted/40 focus:border-primary/30 transition-all text-sm"
                    />
                </div>

                <div className="ml-auto flex items-center gap-2">
                    {isAdmin && (
                        <Popover>
                            <PopoverTrigger asChild>
                                <Button
                                    variant="outline"
                                    size="sm"
                                    disabled={isMembersLoading}
                                    className={cn(
                                        "h-9 justify-start text-left font-normal border-dashed",
                                        !initialUserId && "text-muted-foreground"
                                    )}
                                >
                                    {isMembersLoading ? (
                                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    ) : (
                                        <UserIcon className="mr-2 h-4 w-4" />
                                    )}
                                    {isMembersLoading ? "Loading Members..." : (selectedMember ? `${selectedMember.surname || ""}` : "All Assignees")}
                                </Button>
                            </PopoverTrigger>
                            <PopoverContent className="p-0 w-[200px]" align="end">
                                <Command>
                                    <CommandInput placeholder="Search assignee..." />
                                    <CommandList>
                                        <CommandEmpty>No assignee found.</CommandEmpty>
                                        <CommandGroup>
                                            <CommandItem
                                                onSelect={() => updateFilters({ userId: undefined })}
                                            >
                                                All members
                                            </CommandItem>
                                            {members.map((m) => (
                                                <CommandItem
                                                    key={m.userId}
                                                    onSelect={() => updateFilters({ userId: m.userId })}
                                                >
                                                    {m.surname}
                                                </CommandItem>
                                            ))}
                                        </CommandGroup>
                                    </CommandList>
                                </Command>
                            </PopoverContent>
                        </Popover>
                    )}

                    <Popover>
                        <PopoverTrigger asChild>
                            <Button
                                variant="outline"
                                size="sm"
                                className={cn(
                                    "h-9 justify-start text-left font-normal border-dashed",
                                    !initialDate && "text-muted-foreground"
                                )}
                            >
                                <CalendarIcon className="mr-2 h-4 w-4" />
                                {initialDate ? formatIST(new Date(`${initialDate}T12:00:00`)) : "Any date"}
                            </Button>
                        </PopoverTrigger>
                        <PopoverContent className="w-auto p-0" align="end">
                            <Calendar
                                mode="single"
                                selected={initialDate ? new Date(initialDate) : undefined}
                                onSelect={(date) => updateFilters({ date: date ? formatIST(date, "d MMM yyyy") : undefined })}
                                initialFocus
                            />
                        </PopoverContent>
                    </Popover>

                    {(initialDate || (isAdmin && initialUserId)) && (
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => updateFilters({ date: undefined, userId: undefined })}
                            className="h-9 px-2 text-muted-foreground hover:text-foreground"
                        >
                            <X className="mr-1 h-4 w-4" />
                            Clear
                        </Button>
                    )}
                </div>
            </div>

            <div className="flex-1 overflow-auto relative scrollbar-thin scrollbar-thumb-muted-foreground/20 scrollbar-track-transparent hover:scrollbar-thumb-muted-foreground/40 [&_thead]:sticky [&_thead]:top-0 [&_thead]:z-20 [&_thead]:bg-background/95 [&_thead]:backdrop-blur [&_[data-slot=table-container]]:overflow-visible transition-colors">
                <DataTable
                    columns={reportColumns}
                    data={processedRows}
                    getRowId={(row) => row.id}
                    onRowClick={(row) => {
                        if (row.type === 'date') toggleDate(row.date);
                        else if (row.type === 'user') toggleReport(row.report.id);
                        else if (row.type === 'entry') {
                            setSelectedReport(row.report);
                            setIsDialogOpen(true);
                        }
                    }}
                    showPagination={false}
                    showColumnToggle={false}
                    getRowClassName={(row) => cn(
                        "group transition-colors",
                        row.original.type === "date" && "bg-muted/50 hover:bg-muted/70 font-bold border-t-2 border-border/10",
                        row.original.type === "user" && "bg-muted/10 hover:bg-muted/20 border-t border-border/5",
                        row.original.type === "entry" && "hover:bg-accent/5 cursor-default"
                    )}
                />

                {isLoadingMore ? (
                    <div className="flex justify-center p-8 border-t border-border/10 bg-muted/5">
                        <Loader2 className="h-6 w-6 animate-spin text-primary/60" />
                    </div>
                ) : (hasMore && data.length > 0) ? (
                    <div ref={observerRef} className="h-12 flex items-center justify-center border-t border-border/5" />
                ) : data.length > 0 ? (
                    <div className="p-8 text-center border-t border-border/10 bg-muted/5">
                        <p className="text-sm text-muted-foreground font-medium italic opacity-60">
                            ✨ You've reached the end of the logs
                        </p>
                    </div>
                ) : (
                    <div className="flex flex-col items-center justify-center py-20 bg-muted/5 text-center flex-1">
                        <div className="p-4 rounded-2xl bg-muted/50 mb-4 border border-border/40">
                            <Search className="h-8 w-8 text-muted-foreground/40" />
                        </div>
                        <h3 className="font-semibold text-lg">No reports found</h3>
                        <p className="text-sm text-muted-foreground max-w-xs mx-auto">
                            Try adjusting your filters or search query to find activity logs.
                        </p>
                    </div>
                )}
            </div>

            {selectedReport && (
                <ReportDetailModal
                    report={selectedReport}
                    isOpen={isDialogOpen}
                    onOpenChange={setIsDialogOpen}
                />
            )}
        </div>
    );
}

