import dynamic from "next/dynamic";
import { getWorkspaceTags } from "@/data/tag/get-tags";
import { ProjectService } from "@/server/services/project";
import { getWorkspacePermissions } from "@/data/user/get-user-permissions";
import { requireUser } from "@/lib/auth/require-user";
import { TasksService } from "@/server/services/task/tasks.service";

import type { TaskWithSubTasks } from "@/components/task/shared/types";


const TaskTable = dynamic(() => import("@/components/task/list/task-table"), {
    loading: () => <div className="h-[60vh] w-full flex items-center justify-center text-muted-foreground animate-pulse">Loading Tasks...</div>
});

interface WorkspaceListViewProps {
    workspaceId: string;
}

export async function WorkspaceListView({
    workspaceId,
}: WorkspaceListViewProps) {
    // Get current user
    const user = await requireUser();

    // 1. Fetch projects first to determine visual order for task preloading
    const projects = await ProjectService.getWorkspaceProjects(workspaceId, user.id);
    const topProjectIds = projects
        .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
        .slice(0, 3)
        .map(p => p.id);

    // 2. Fetch initial tasks for the top projects and metadata in parallel
    const viewStartTime = performance.now();
    const [projectMembers, permissions, tasksData] = await Promise.all([
        ProjectService.getWorkspaceProjectMembers(workspaceId),
        getWorkspacePermissions(workspaceId),
        TasksService.getTasks({
            workspaceId,
            hierarchyMode: "parents",
            includeSubTasks: false,
            limit: 50,
            expandedProjectIds: topProjectIds, // 🎯 SSR Optimization: Preload tasks for top 3 projects
            includeFacets: true,
            view_mode: "list",
            // description is omitted for performance (TEXT column)
        }, user.id),
    ]);
    const duration = performance.now() - viewStartTime;
    if (duration > 500) {
        console.warn(`[PERF_WARN] WorkspaceListView rendered in ${duration.toFixed(2)}ms`);
    }

    const formattedMembers = projectMembers;

    // Handle union response safely
    const rawTasks = (tasksData as any).tasks || [];
    const initialTasks = rawTasks.map((t: any) => ({
        ...t,
        subtaskCount: t.subtaskCount ?? t._count?.subTasks ?? 0,
        subTasks: undefined
    })) as TaskWithSubTasks[];

    return (
        <TaskTable
            initialTasks={initialTasks}
            initialHasMore={tasksData.hasMore}
            initialNextCursor={tasksData.nextCursor}
            initialTotalCount={tasksData.totalCount ?? undefined}
            members={formattedMembers as any}
            workspaceId={workspaceId}
            projectId=""
            canCreateSubTask={permissions.hasAccess}
            level="workspace"
            userId={user.id}
            projectCounts={tasksData.facets?.projects || {}}
        />
    );
}

"use client";

import { useEffect, useState, useMemo, useCallback } from "react";
import { useShallow } from "zustand/react/shallow";
import { DataTable } from "@/components/data-table/data-table";
import { ColumnDef } from "@tanstack/react-table";
import { format, addMonths, subMonths, startOfMonth, endOfMonth } from "date-fns";
import { APP_DATE_FORMAT, cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { useMounted } from "@/hooks/use-mounted";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { UserMinus, Loader2, LogIn, ChevronLeft, ChevronRight, CalendarDays } from "lucide-react";
import { AttendanceLogger } from "./attendance-logger";
import { Calendar as ShadcnCalendar } from "@/components/ui/calendar";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Dialog, DialogContent, DialogTrigger, DialogTitle } from "@/components/ui/dialog";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { MapPin, Clock, Filter, X, Calendar as CalendarIcon } from "lucide-react";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useWorkspaceMemberStore, useRealtimeMemberSync, EMPTY_ARRAY } from "@/lib/store/workspace-member-store";
import { useTeamQueryStore } from "@/lib/store/team-query-store";

interface AttendanceRecord {
    id: string;
    date: string;
    checkIn: string;
    checkOut: string | null;
    status: string;
    isOvertime: boolean;
    checkInLatitude: number | null;
    checkInLongitude: number | null;
    checkOutLatitude: number | null;
    checkOutLongitude: number | null;
    checkInAddress: string | null;
    checkOutAddress: string | null;
    notes: string | null;
    checkInNotes: string | null;
    checkOutNotes: string | null;
    WorkspaceMember: {
        id: string;
        casualLeaveBalance: number;
        sickLeaveBalance: number;
        user: {
            name: string;
            surname: string;
            email: string;
        };
    };
}

export function AttendanceTable({
    workspaceId,
    isWorkspaceAdmin,
    workspaceRole,
}: {
    workspaceId: string;
    isWorkspaceAdmin: boolean;
    workspaceRole: "OWNER" | "ADMIN" | "MANAGER" | "MEMBER";
}) {
    const isPowerUser = isWorkspaceAdmin || workspaceRole === "MANAGER";
    const [loading, setLoading] = useState(true);
    const [records, setRecords] = useState<AttendanceRecord[]>([]);
    const [totalCount, setTotalCount] = useState(0);
    const [pageIndex, setPageIndex] = useState(0);
    const [pageSize, setPageSize] = useState(10);
    const [search, setSearch] = useState("");
    const [debouncedSearch, setDebouncedSearch] = useState("");

    // Debounce search
    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedSearch(search);
            setPageIndex(0); // Reset to first page when search changes
        }, 500);
        return () => clearTimeout(timer);
    }, [search]);

    const [selectedDate, setSelectedDate] = useState(new Date());

    // Main filters state (synced with API)
    const [activeFilters, setActiveFilters] = useState<{
        from: Date | undefined;
        to: Date | undefined;
        memberId: string | undefined;
        status: string | undefined;
    }>({
        from: startOfMonth(new Date()),
        to: endOfMonth(new Date()),
        memberId: undefined,
        status: undefined,
    });

    // Helper to flatten Prisma records into the shape the table expects
    const flattenRecord = (r: any) => {
        if (!r) return r;
        // If it's already flat (has memberSurname), return it
        if (r.memberSurname) return r;
        // If it's nested (Prisma), flatten it
        return {
            ...r,
            memberSurname: r.WorkspaceMember?.user?.surname || "User",
            memberEmail: r.WorkspaceMember?.user?.email || "",
            workspaceMember: r.WorkspaceMember
        };
    };

    useEffect(() => {
        const handler = (e: any) => {
            const { action, record, oldRecord } = e.detail || {};
            const flatRecord = flattenRecord(record);

            console.log(`[AttendanceTable][SURGICAL_V2] 🔄 Event received: ${action}`, {
                record: flatRecord,
                original: record
            });

            // 1. Handle New Check-ins
            if (flatRecord && action === "CHECKED_IN") {
                setRecords(prev => {
                    if (prev.some(r => r.id === flatRecord.id)) return prev;
                    return [flatRecord, ...prev];
                });
                setTotalCount(prev => prev + 1);
                return;
            }

            // 2. Handle Updates (Check-outs, etc.)
            const updateActions = ["CHECKED_OUT", "ATTENDANCE_UPDATED"];
            if (flatRecord && updateActions.includes(action)) {
                setRecords(prev => prev.map(r => r.id === flatRecord.id ? flatRecord : r));
                return;
            }

            // 3. Handle Deletions
            if (action === "ATTENDANCE_DELETED") {
                const deletedId = record?.id || oldRecord?.id;
                if (deletedId) {
                    setRecords(prev => prev.filter(r => r.id !== deletedId));
                    setTotalCount(prev => Math.max(0, prev - 1));
                    return;
                }
            }

            // ⛔ BLOCK Fallback for all known attendance actions to prevent the fetch
            if (action?.startsWith("ATTENDANCE_") || action?.startsWith("CHECKED_")) {
                console.log(`[AttendanceTable] ✅ Surgical update complete for ${action}. No fetch required.`);
                return;
            }

            // Fallback for unknown structural changes
            if (action === "team_update" || !action) {
                console.log(`[AttendanceTable] ⚠️ Unknown action, falling back to fetch...`);
                fetchRecords(true, true);
            }
        };
        window.addEventListener("realtime-attendance-sync", handler);
        return () => window.removeEventListener("realtime-attendance-sync", handler);
    }, [workspaceId, pageIndex, pageSize, activeFilters]);

    // Local state for the filter popover
    const [tempFilters, setTempFilters] = useState(activeFilters);
    const [isFilterOpen, setIsFilterOpen] = useState(false);

    const mounted = useMounted();

    // Use the slim members list for filters to ensure ALL members are available without performance burden
    const slimMembers = useWorkspaceMemberStore(
        useShallow((state) => state.slimMembersByWorkspace[workspaceId] || EMPTY_ARRAY)
    );

    // Subscribe to real-time updates for this workspace
    useRealtimeMemberSync(workspaceId);

    // Fetch slim members for filter (robust & fast)
    useEffect(() => {
        useWorkspaceMemberStore.getState().fetchSlimMembers(workspaceId);
    }, [workspaceId]);



    // Memoize options from slim members
    const memberOptions = useMemo(() => {
        if (!slimMembers.length) return [];
        return slimMembers
            .map(m => ({
                label: `${m.surname || ""}`.trim(),
                value: m.id
            }));
    }, [slimMembers]);

    const isValidDate = (d: any) => d instanceof Date && !isNaN(d.getTime());

    const handleMonthChange = (direction: 'prev' | 'next') => {
        const newDate = direction === 'prev' ? subMonths(selectedDate, 1) : addMonths(selectedDate, 1);
        setSelectedDate(newDate);
        setActiveFilters(prev => ({
            ...prev,
            from: startOfMonth(newDate),
            to: endOfMonth(newDate)
        }));
    };

    const { setIsQuerying } = useTeamQueryStore();

    const fetchRecords = useCallback(async (force = false, silent = false) => {
        try {
            setIsQuerying(true);
            console.log(`[AttendanceTable] Fetching records with filters:`, {
                workspaceId,
                from: activeFilters.from?.toISOString(),
                to: activeFilters.to?.toISOString(),
                memberId: activeFilters.memberId,
                status: activeFilters.status,
                silent
            });
            if (!silent) setLoading(true);
            const params = new URLSearchParams();
            if (activeFilters.from && isValidDate(activeFilters.from)) params.append("startDate", activeFilters.from.toISOString());
            if (activeFilters.to && isValidDate(activeFilters.to)) params.append("endDate", activeFilters.to.toISOString());
            if (activeFilters.memberId) params.append("memberId", activeFilters.memberId);
            if (activeFilters.status) params.append("status", activeFilters.status);
            if (debouncedSearch) params.append("search", debouncedSearch);
            params.append("page", (pageIndex + 1).toString());
            params.append("pageSize", pageSize.toString());

            const url = `/api/v1/attendance?${params.toString()}${force ? '&refresh=true' : ''}`;
            const res = await fetch(url, {
                headers: { "x-workspace-id": workspaceId },
                cache: 'no-store' // Ensure we don't get cached browser results
            });
            const data = await res.json();
            if (data.success) {
                console.log(`[AttendanceTable] Records successfully loaded: ${data.data?.length || 0} items`);
                setRecords(data.data || []);
                setTotalCount(data.totalCount || 0);
            } else {
                console.error("[AttendanceTable] API returned error:", data.error);
                toast.error(data.error || "Failed to load records");
            }
        } catch (error) {
            console.error("[AttendanceTable] Fetch exception:", error);
            toast.error("Failed to load attendance records");
        } finally {
            setLoading(false);
            setIsQuerying(false);
        }
    }, [
        workspaceId,
        pageIndex,
        pageSize,
        activeFilters.from?.getTime(),
        activeFilters.to?.getTime(),
        activeFilters.memberId,
        activeFilters.status,
        debouncedSearch,
        setIsQuerying
    ]);

    useEffect(() => {
        fetchRecords();
    }, [fetchRecords]);

    // Sync temp filters with active filters when popover opens
    useEffect(() => {
        if (isFilterOpen) {
            setTempFilters(activeFilters);
        }
    }, [isFilterOpen, activeFilters]);

    const columns = useMemo<ColumnDef<AttendanceRecord>[]>(() => [
        {
            id: "memberId",
            accessorKey: "WorkspaceMember.user.name",
            header: "Member",
            meta: { className: "min-w-[200px]" },
            cell: ({ row }) => {
                const user = row.original.WorkspaceMember?.user;
                if (!user) return <div className="text-sm italic text-muted-foreground">Unknown Member</div>;
                const initials = (user.surname?.[0]).toUpperCase();
                return (
                    <div className="flex items-center gap-3">
                        <Avatar className="h-9 w-9">
                            <AvatarFallback>{initials}</AvatarFallback>
                        </Avatar>
                        <div className="flex flex-col">
                            <span className="font-medium text-sm text-foreground">
                                {user.surname}
                            </span>
                            <span className="text-[10px] text-muted-foreground/80 truncate max-w-[140px]">
                                {user.email}
                            </span>
                        </div>
                    </div>
                );
            },
        },
        {
            accessorKey: "date",
            header: "Date",
            meta: { className: "min-w-[120px]" },
            cell: ({ row }) => {
                if (!mounted) return "...";
                try {
                    const d = new Date(row.original.date);
                    if (!isValidDate(d)) return <span className="text-xs text-muted-foreground italic">Invalid Date</span>;
                    return (
                        <div className="text-sm text-foreground/80">
                            {format(d, APP_DATE_FORMAT)}
                        </div>
                    );
                } catch (e) {
                    return <span className="text-xs text-rose-500 italic">Error</span>;
                }
            },
        },
        {
            accessorKey: "checkIn",
            header: "Check-In",
            meta: { className: "min-w-[110px]" },
            cell: ({ row }) => {
                if (!mounted) return "...";
                const checkIn = row.original.checkIn;
                if (!checkIn) return <div className="text-xs text-muted-foreground italic">—</div>;
                try {
                    const d = new Date(checkIn);
                    if (!isValidDate(d)) return <div className="text-xs text-muted-foreground italic">—</div>;
                    return (
                        <div className="flex flex-col items-start">
                            <div className="flex items-center gap-1.5 text-sm text-emerald-600">
                                <Clock className="h-3.5 w-3.5" />
                                {format(d, "hh:mm a")}
                            </div>
                        </div>
                    );
                } catch (e) {
                    return <div className="text-xs text-muted-foreground italic">—</div>;
                }
            },
        },
        {
            id: "inLocation",
            header: "In-Location",
            meta: { className: "min-w-[150px]" },
            cell: ({ row }) => {
                const lat = row.original.checkInLatitude;
                const lng = row.original.checkInLongitude;
                const address = row.original.checkInAddress;
                const hasNote = !!row.original.notes;

                if (!lat || !lng) return <div className="text-xs text-muted-foreground italic">—</div>;
                return (
                    <div className="flex justify-start">
                        <a
                            href={`https://www.google.com/maps?q=${lat},${lng}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            className={cn(
                                "flex items-center gap-1.5 text-[10px] hover:underline transition-all group",
                                hasNote ? "text-rose-600 font-medium" : "text-primary/70 hover:text-primary"
                            )}
                            title={address || `Raw coordinates: ${lat}, ${lng}`}
                        >
                            <MapPin className={cn("h-3 w-3 shrink-0 group-hover:scale-110 transition-transform", hasNote ? "text-rose-600" : "text-rose-500")} />
                            <span className="truncate uppercase tracking-tighter max-w-[120px]">
                                {hasNote ? "Other Location" : (address || `${lat.toFixed(4)}, ${lng.toFixed(4)}`)}
                            </span>
                        </a>
                    </div>
                );
            },
        },
        {
            accessorKey: "checkOut",
            header: "Check-Out",
            meta: { className: "min-w-[110px]" },
            cell: ({ row }) => {
                if (!mounted) return "...";
                const checkIn = row.original.checkIn;
                const checkOut = row.original.checkOut;
                if (!checkOut) return <div className="text-xs text-muted-foreground italic">—</div>;

                try {
                    const dIn = checkIn ? new Date(checkIn) : null;
                    const dOut = new Date(checkOut);
                    if (!isValidDate(dOut)) return <div className="text-xs text-muted-foreground italic">—</div>;

                    const isNextDay = (dIn && isValidDate(dIn) &&
                        (dOut.getDate() !== dIn.getDate() || dOut.getMonth() !== dIn.getMonth())) ||
                        row.original.notes?.includes("test-night");

                    return (
                        <div className="flex flex-col items-start gap-1">
                            <div className="flex items-center gap-1.5 text-sm text-rose-600">
                                <Clock className="h-3.5 w-3.5" />
                                {format(dOut, "hh:mm a")}
                                {isNextDay && (
                                    <Badge variant="outline" className="px-1 py-0 h-4 text-[9px] font-medium border-amber-200 bg-amber-50 text-amber-600">
                                        +1 DAY
                                    </Badge>
                                )}
                            </div>
                        </div>
                    );
                } catch (e) {
                    return <div className="text-xs text-muted-foreground italic">—</div>;
                }
            },
        },
        {
            id: "outLocation",
            header: "Out-Location",
            meta: { className: "min-w-[150px]" },
            cell: ({ row }) => {
                const lat = row.original.checkOutLatitude;
                const lng = row.original.checkOutLongitude;
                const address = row.original.checkOutAddress;
                const hasNote = !!row.original.notes;

                if (!lat || !lng) return <div className="text-xs text-muted-foreground italic">—</div>;
                return (
                    <div className="flex justify-start">
                        <a
                            href={`https://www.google.com/maps?q=${lat},${lng}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            className={cn(
                                "flex items-center gap-1.5 text-[10px] hover:underline transition-all group",
                                hasNote ? "text-rose-600 font-medium" : "text-primary/70 hover:text-primary"
                            )}
                            title={address || `Raw coordinates: ${lat}, ${lng}`}
                        >
                            <MapPin className={cn("h-3 w-3 shrink-0 group-hover:scale-110 transition-transform", hasNote ? "text-rose-600" : "text-rose-500")} />
                            <span className="truncate uppercase tracking-tighter max-w-[120px]">
                                {hasNote ? "Other Location" : (address || `${lat.toFixed(4)}, ${lng.toFixed(4)}`)}
                            </span>
                        </a>
                    </div>
                );
            },
        },
        {
            id: "duration",
            header: "Duration",
            meta: { className: "min-w-[100px]" },
            cell: ({ row }) => {
                if (!mounted) return "...";
                const checkIn = row.original.checkIn;
                const checkOut = row.original.checkOut;

                if (!checkIn || !checkOut) return <div className="text-xs text-muted-foreground italic">—</div>;

                try {
                    const start = new Date(checkIn);
                    const end = new Date(checkOut);

                    if (!isValidDate(start) || !isValidDate(end)) return <div className="text-xs text-muted-foreground italic">—</div>;

                    const diffMs = end.getTime() - start.getTime();
                    if (isNaN(diffMs) || diffMs < 0) return <div className="text-xs text-muted-foreground italic">—</div>;

                    const diffHrs = Math.floor(diffMs / (1000 * 60 * 60));
                    const diffMins = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));

                    return (
                        <div className="flex items-center gap-1.5 font-medium text-sm text-primary/80">
                            <Clock className="h-3.5 w-3.5" />
                            {diffHrs}h {diffMins}m
                        </div>
                    );
                } catch (e) {
                    return <div className="text-xs text-muted-foreground italic">—</div>;
                }
            }
        },
        {
            accessorKey: "status",
            header: "Status",
            meta: { className: "min-w-[120px]" },
            cell: ({ row }) => {
                const status = row.original.status;
                let content;
                switch (status) {
                    case "PRESENT":
                        content = <Badge className="bg-emerald-500/10 text-emerald-600 hover:bg-emerald-500/20 border-emerald-500/20 font-medium">Present</Badge>;
                        break;
                    case "ABSENT":
                        content = <Badge variant="destructive" className="font-medium">Absent</Badge>;
                        break;
                    case "LATE":
                        content = <Badge className="bg-amber-500/10 text-amber-600 hover:bg-amber-500/20 border-amber-500/20 font-medium">Late</Badge>;
                        break;
                    case "HALF_DAY":
                        content = <Badge className="bg-orange-500/10 text-orange-600 hover:bg-orange-500/20 border-orange-500/20 font-medium">Half Day</Badge>;
                        break;
                    case "ON_LEAVE":
                        content = <Badge className="bg-purple-500/10 text-purple-600 hover:bg-purple-500/20 border-purple-500/20 font-medium">On Leave</Badge>;
                        break;
                    default:
                        content = <Badge variant="outline" className="font-medium">{status}</Badge>;
                }
                return (
                    <div className="flex justify-start items-center gap-2">
                        {content}
                        {row.original.isOvertime && (
                            <Badge className="bg-purple-500/10 text-purple-600 hover:bg-purple-500/20 border-purple-500/20 px-1.5 py-0 text-[10px] font-medium">
                                OT
                            </Badge>
                        )}
                    </div>
                );
            },
        },
        {
            accessorKey: "checkInNotes",
            header: "In-Notes",
            meta: { className: "min-w-[150px]" },
            cell: ({ row }) => {
                const notes = row.original.checkInNotes;
                if (!notes) return <div className="text-xs text-muted-foreground italic">—</div>;
                return (
                    <div className="max-w-[150px] truncate text-xs font-medium text-foreground/60" title={notes}>
                        {notes}
                    </div>
                );
            },
        },
        {
            accessorKey: "checkOutNotes",
            header: "Out-Notes",
            meta: { className: "min-w-[150px]" },
            cell: ({ row }) => {
                const notes = row.original.checkOutNotes;
                if (!notes) return <div className="text-xs text-muted-foreground italic">—</div>;
                return (
                    <div className="max-w-[150px] truncate text-xs font-medium text-foreground/60" title={notes}>
                        {notes}
                    </div>
                );
            },
        },
    ], [mounted]);

    const stats = useMemo(() => {
        const counts = { present: 0, late: 0, halfDay: 0, absent: 0, leave: 0, total: records.length };
        records.forEach(r => {
            if (r.status === "PRESENT") counts.present++;
            if (r.status === "LATE") counts.late++;
            if (r.status === "HALF_DAY") counts.halfDay++;
            if (r.status === "ABSENT") counts.absent++;
            if (r.status === "ON_LEAVE") counts.leave++;
        });
        return counts;
    }, [records]);

    const selectedMember = useMemo(() => {
        if (!activeFilters.memberId) return null;
        return slimMembers.find((m: any) => m.id === activeFilters.memberId);
    }, [slimMembers, activeFilters.memberId]);

    const handleApplyFilters = () => {
        setActiveFilters(tempFilters);
        setIsFilterOpen(false);
    };

    const handleResetFilters = () => {
        const reset = {
            from: undefined,
            to: undefined,
            memberId: undefined,
            status: undefined,
        };
        setTempFilters(reset);
        setActiveFilters(reset);
        setIsFilterOpen(false);
    };

    const activeFilterCount = useMemo(() => {
        let count = 0;
        if (activeFilters.memberId) count++;
        if (activeFilters.status) count++;
        if (activeFilters.from || activeFilters.to) count++;
        return count;
    }, [activeFilters]);

    const [isReconciling, setIsReconciling] = useState(false);

    const handleReconcile = async () => {
        try {
            setIsReconciling(true);
            const res = await fetch("/api/v1/attendance/reconcile", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "x-workspace-id": workspaceId
                },
                body: JSON.stringify({ date: new Date().toISOString() })
            });
            const data = await res.json();
            if (data.success) {
                toast.success(`Successfully reconciled. Marked ${data.data.count} members as absent.`);
                fetchRecords();
            } else {
                toast.error(data.error || "Failed to reconcile attendance");
            }
        } catch (error) {
            toast.error("An error occurred during reconciliation");
        } finally {
            setIsReconciling(false);
        }
    };

    const extraToolbarContent = (
        <div className="flex items-center gap-2">
            <Dialog>
                <DialogTrigger asChild>
                    <Button
                        size="sm"
                        className="h-9 px-3 gap-2 bg-primary hover:bg-primary/90 shadow-sm transition-all active:scale-95"
                    >
                        <LogIn className="h-4 w-4" />
                        <span className="font-medium text-sm hidden sm:inline">Mark Attendance</span>
                    </Button>
                </DialogTrigger>
                <DialogContent className="p-0 border-none bg-transparent shadow-none max-w-sm">
                    <DialogTitle className="sr-only">Mark Attendance</DialogTitle>
                    <AttendanceLogger workspaceId={workspaceId} />
                </DialogContent>
            </Dialog>

            {isPowerUser && (
                <Button
                    variant="outline"
                    size="sm"
                    onClick={handleReconcile}
                    disabled={isReconciling}
                    className="h-9 px-3 gap-2 border-dashed border-rose-200 text-rose-600 hover:bg-rose-50 hover:text-rose-700"
                >
                    {isReconciling ? (
                        <Loader2 className="h-4 w-4 animate-spin" />
                    ) : (
                        <UserMinus className="h-4 w-4" />
                    )}
                    <span className="font-medium text-sm hidden sm:inline">Mark Absents</span>
                </Button>
            )}

            <Popover open={isFilterOpen} onOpenChange={setIsFilterOpen}>
                <PopoverTrigger asChild>
                    <Button
                        variant="outline"
                        className="gap-2 relative h-9 px-3 border shadow-sm hover:bg-accent/50 transition-colors"
                    >
                        <Filter className="h-4 w-4" />
                        <span className="font-medium text-sm">Filters</span>
                        {activeFilterCount > 0 && (
                            <Badge
                                variant="destructive"
                                className="absolute -top-2 -right-2 h-5 w-5 rounded-full p-0 flex items-center justify-center text-[10px] font-medium shadow-md animate-in zoom-in"
                            >
                                {activeFilterCount}
                            </Badge>
                        )}
                    </Button>
                </PopoverTrigger>
                <PopoverContent
                    className="w-[calc(100vw-2rem)] sm:w-[500px] p-0 overflow-hidden rounded-xl border-none shadow-2xl shadow-black/20"
                    align="end"
                    side="bottom"
                    sideOffset={8}
                >
                    {/* Header */}
                    <div className="flex items-center justify-between border-b bg-muted/30 px-5 py-4">
                        <div className="flex items-center gap-2">
                            <Filter className="h-4 w-4 text-primary" />
                            <h3 className="text-base font-medium text-foreground">Filters</h3>
                        </div>
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => setIsFilterOpen(false)}
                            className="h-8 w-8 p-0 rounded-full hover:bg-background/80"
                        >
                            <X className="h-4 w-4" />
                        </Button>
                    </div>

                    {/* Content - Scrollable */}
                    <div className="max-h-[65vh] overflow-y-auto p-5 custom-scrollbar bg-background/50 backdrop-blur-sm">
                        {/* Filters Grid */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-6">

                            {/* Member Filter */}
                            {isPowerUser && (
                                <div className="space-y-3">
                                    <div className="flex items-center justify-between">
                                        <h4 className="text-[11px] font-medium uppercase tracking-widest text-muted-foreground/80">Member</h4>
                                        {tempFilters.memberId && (
                                            <Button
                                                variant="ghost"
                                                size="sm"
                                                onClick={() => setTempFilters(prev => ({ ...prev, memberId: undefined }))}
                                                className="h-auto p-0 text-[10px] font-medium text-primary hover:text-primary/80 hover:bg-transparent"
                                            >
                                                CLEAR
                                            </Button>
                                        )}
                                    </div>
                                    <Select
                                        value={tempFilters.memberId || "all"}
                                        onValueChange={(val) => setTempFilters(prev => ({ ...prev, memberId: val === "all" ? undefined : val }))}
                                    >
                                        <SelectTrigger className="h-10 bg-background/50 border-muted-foreground/20 focus:ring-primary/20">
                                            <SelectValue placeholder="All Members" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Members</SelectItem>
                                            {memberOptions.map((m) => (
                                                <SelectItem key={m.value} value={m.value} className="text-sm">
                                                    {m.label}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                            )}

                            {/* Status Filter */}
                            <div className="space-y-3">
                                <div className="flex items-center justify-between">
                                    <h4 className="text-[11px] font-medium uppercase tracking-widest text-muted-foreground/80">Status</h4>
                                    {tempFilters.status && (
                                        <Button
                                            variant="ghost"
                                            size="sm"
                                            onClick={() => setTempFilters(prev => ({ ...prev, status: undefined }))}
                                            className="h-auto p-0 text-[10px] font-medium text-primary hover:text-primary/80 hover:bg-transparent"
                                        >
                                            CLEAR
                                        </Button>
                                    )}
                                </div>
                                <Select
                                    value={tempFilters.status || "all"}
                                    onValueChange={(val) => setTempFilters(prev => ({ ...prev, status: val === "all" ? undefined : val }))}
                                >
                                    <SelectTrigger className="h-10 bg-background/50 border-muted-foreground/20 focus:ring-primary/20">
                                        <SelectValue placeholder="All Status" />
                                    </SelectTrigger>
                                    <SelectContent>
                                        <SelectItem value="all">All Status</SelectItem>
                                        <SelectItem value="PRESENT" className="text-sm">Present</SelectItem>
                                        <SelectItem value="ABSENT" className="text-sm">Absent</SelectItem>
                                        <SelectItem value="LATE" className="text-sm">Late</SelectItem>
                                        <SelectItem value="HALF_DAY" className="text-sm">Half Day</SelectItem>
                                        <SelectItem value="ON_LEAVE" className="text-sm">On Leave</SelectItem>
                                    </SelectContent>
                                </Select>
                            </div>

                            {/* Date Range Filter */}
                            <div className="space-y-3">
                                <div className="flex items-center justify-between">
                                    <h4 className="text-[11px] font-medium uppercase tracking-widest text-muted-foreground/80">Date Range</h4>
                                    {(tempFilters.from || tempFilters.to) && (
                                        <Button
                                            variant="ghost"
                                            size="sm"
                                            onClick={() => setTempFilters(prev => ({
                                                ...prev,
                                                from: undefined,
                                                to: undefined
                                            }))}
                                            className="h-auto p-0 text-[10px] font-medium text-primary hover:text-primary/80 hover:bg-transparent"
                                        >
                                            RESET
                                        </Button>
                                    )}
                                </div>
                                <Popover>
                                    <PopoverTrigger asChild>
                                        <Button
                                            variant="outline"
                                            className={cn(
                                                "w-full justify-start text-left font-normal h-10 px-3 bg-background/50 border-muted-foreground/20 hover:bg-accent/30",
                                                !tempFilters.from && !tempFilters.to && "text-muted-foreground"
                                            )}
                                        >
                                            <CalendarIcon className="mr-2 h-4 w-4 text-muted-foreground" />
                                            <span className="truncate text-sm">
                                                {tempFilters.from && tempFilters.to ? (
                                                    <>{format(tempFilters.from, "MMM d")} - {format(tempFilters.to, "MMM d")}</>
                                                ) : tempFilters.from ? (
                                                    <>{format(tempFilters.from, "MMM d")} - ...</>
                                                ) : (
                                                    "Pick dates"
                                                )}
                                            </span>
                                        </Button>
                                    </PopoverTrigger>
                                    <PopoverContent className="w-auto p-0 border-none shadow-2xl rounded-xl overflow-hidden" align="start">
                                        <div className="bg-background">
                                            <ShadcnCalendar
                                                mode="range"
                                                selected={{
                                                    from: tempFilters.from,
                                                    to: tempFilters.to,
                                                }}
                                                onSelect={(range) => {
                                                    setTempFilters(prev => ({
                                                        ...prev,
                                                        from: range?.from,
                                                        to: range?.to,
                                                    }));
                                                }}
                                                initialFocus
                                                className="p-3"
                                            />
                                        </div>
                                    </PopoverContent>
                                </Popover>
                            </div>
                        </div>
                    </div>

                    {/* Footer Actions */}
                    <div className="flex items-center gap-3 border-t bg-muted/20 px-5 py-4">
                        <Button
                            variant="ghost"
                            onClick={handleResetFilters}
                            className="flex-1 font-medium text-sm h-10 hover:bg-background/80"
                        >
                            Reset All
                        </Button>
                        <Button
                            onClick={handleApplyFilters}
                            className="flex-[2] font-medium text-sm h-10 bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 transition-all active:scale-95"
                        >
                            Apply Filters
                        </Button>
                    </div>
                </PopoverContent>
            </Popover>
        </div>
    );

    if (!mounted) return null;

    return (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-start">
            <div className="lg:col-span-10 space-y-6">
                <DataTable
                    columns={columns}
                    data={records}
                    isLoading={loading}
                    searchKey="memberId"
                    searchPlaceholder="Search members..."
                    extraToolbarContent={extraToolbarContent}
                    pageIndex={pageIndex}
                    pageSize={pageSize}
                    rowCount={totalCount}
                    manualPagination={true}
                    manualFiltering={true}
                    containerClassName="max-h-[calc(100vh-300px)]"
                    onPaginationChange={(p) => {
                        setPageIndex(p.pageIndex);
                        setPageSize(p.pageSize);
                    }}
                    onFilterChange={(filters) => {
                        const searchFilter = filters.find(f => f.id === "memberId");
                        const searchValue = searchFilter?.value as string || "";
                        setSearch(searchValue);
                    }}
                />
            </div>

            <div className="lg:col-span-2 sticky top-6">
                <div className="space-y-6">
                    {/* Month Navigator - Clean Full Width Style */}
                    <div className="flex items-center justify-between px-1">
                        <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8 rounded-full hover:bg-primary/10 hover:text-primary transition-all active:scale-90"
                            onClick={() => handleMonthChange('prev')}
                        >
                            <ChevronLeft className="h-4 w-4" />
                        </Button>
                        <div className="flex flex-col items-center">
                            <span className="text-sm font-medium text-foreground tracking-tight">
                                {format(selectedDate, "MMMM yyyy")}
                            </span>
                        </div>
                        <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8 rounded-full hover:bg-primary/10 hover:text-primary transition-all active:scale-90"
                            onClick={() => handleMonthChange('next')}
                        >
                            <ChevronRight className="h-4 w-4" />
                        </Button>
                    </div>

                    {/* Main Stats Card */}
                    <div className="p-4 rounded-xl border bg-card/30 backdrop-blur-md border-muted-foreground/20 relative overflow-hidden group shadow-sm">
                        <h3 className="text-sm font-medium uppercase tracking-widest text-muted-foreground mb-6 flex items-center gap-2">
                            <CalendarDays className="h-4 w-4 text-primary" />
                            Summary
                        </h3>

                        <div>
                            <div className="flex items-center justify-between rounded-lg">
                                <span className="text-sm font-medium text-muted-foreground">Total:</span>
                                <span className="text-lg font-normal tabular-nums">{stats.total}</span>
                            </div>
                            <div className="flex items-center justify-between rounded-lg">
                                <span className="text-sm font-medium text-emerald-600/70">On Time:</span>
                                <span className="text-lg font-normal tabular-nums text-emerald-600">{stats.present}</span>
                            </div>
                            <div className="flex items-center justify-between rounded-lg">
                                <span className="text-sm font-medium text-amber-600/70">Late:</span>
                                <span className="text-lg font-normal tabular-nums text-amber-600">{stats.late}</span>
                            </div>
                            <div className="flex items-center justify-between rounded-lg">
                                <span className="text-sm font-medium text-orange-600/70">Half Day:</span>
                                <span className="text-lg font-normal tabular-nums text-orange-600">{stats.halfDay}</span>
                            </div>
                            <div className="flex items-center justify-between rounded-lg">
                                <span className="text-sm font-medium text-purple-600/70">Leave:</span>
                                <span className="text-lg font-normal tabular-nums text-purple-600">{stats.leave}</span>
                            </div>
                            <div className="flex items-center justify-between rounded-lg">
                                <span className="text-sm font-medium text-rose-600/70">Absent:</span>
                                <span className="text-lg font-normal tabular-nums text-rose-600">{stats.absent}</span>
                            </div>
                        </div>
                    </div>

                    {/* Member Specific Balances */}
                    {selectedMember && (
                        <div className="p-4 rounded-lg border bg-card/30 backdrop-blur-md border-muted-foreground/20">
                            <h3 className="text-sm font-normal uppercase tracking-widest text-muted-foreground/80 mb-4 flex items-center gap-2">
                                Leave Balances
                            </h3>
                            <div className="space-y-0">
                                <div className="flex items-center justify-between">
                                    <div className="text-[13px] font-medium uppercase tracking-tighter text-purple-600/70 mb-1">Casual Leave</div>
                                    <div className="text-lg font-normal text-purple-600">
                                        {Math.max(0, selectedMember.casualLeaveBalance || 0)}
                                    </div>
                                </div>
                                <div className="flex items-center justify-between">
                                    <div className="text-[13px] font-medium uppercase tracking-tighter text-blue-600/70 mb-1">Sick Leave</div>
                                    <div className="text-lg font-normal text-blue-600">
                                        {Math.max(0, selectedMember.sickLeaveBalance || 0)}
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, useMemo } from "react";
import { DataTable } from "@/components/data-table/data-table";
import { ColumnDef } from "@tanstack/react-table";
import { format } from "date-fns";
import { cn } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { useMounted } from "@/hooks/use-mounted";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { Check, X, Loader2, Calendar as CalendarIcon, User, Info } from "lucide-react";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { useTeamQueryStore } from "@/lib/store/team-query-store";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";

interface LeaveRequest {
    id: string;
    startDate: string;
    endDate: string;
    reason: string;
    status: "PENDING" | "APPROVED" | "REJECTED";
    type: "CASUAL" | "SICK";
    createdAt: string;
    surname: string;
    name: string;
    email: string;
    image: string | null;
    workspaceMemberId: string;
    reportToId: string | null;
    casualLeaveBalance: number;
    sickLeaveBalance: number;
    processedByName?: string | null;
}

export function LeavesTable({
    workspaceId,
    isWorkspaceAdmin,
    workspaceRole,
    currentMemberId,
}: {
    workspaceId: string;
    isWorkspaceAdmin: boolean;
    workspaceRole: "OWNER" | "ADMIN" | "MANAGER" | "MEMBER";
    currentMemberId: string;
}) {
    const isOwnerOrAdmin = workspaceRole === "OWNER" || workspaceRole === "ADMIN";
    const [loading, setLoading] = useState(true);
    const [requests, setRequests] = useState<LeaveRequest[]>([]);
    const [totalCount, setTotalCount] = useState(0);
    const [pageIndex, setPageIndex] = useState(0);
    const [pageSize, setPageSize] = useState(10);
    const [search, setSearch] = useState("");
    const [debouncedSearch, setDebouncedSearch] = useState("");

    // Debounce search
    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedSearch(search);
            setPageIndex(0); // Reset to first page when search changes
        }, 500);
        return () => clearTimeout(timer);
    }, [search]);

    const mounted = useMounted();

    // Helper to flatten Prisma records into the shape the table expects
    const flattenRecord = (r: any) => {
        if (!r) return r;
        // If it's already flat (has surname), return it
        if (r.surname) return r;
        // If it's nested (Prisma), flatten it
        return {
            ...r,
            surname: r.WorkspaceMember?.user?.surname || "User",
            email: r.WorkspaceMember?.user?.email || "",
            casualLeaveBalance: r.WorkspaceMember?.casualLeaveBalance || 0,
            sickLeaveBalance: r.WorkspaceMember?.sickLeaveBalance || 0,
            processedByName: r.processedBy?.user?.surname || r.processedByName || null,
        };
    };

    useEffect(() => {
        const handler = (e: any) => {
            const { action, record, oldRecord } = e.detail || {};
            const flatRecord = flattenRecord(record);

            console.log(`[LeavesTable][SURGICAL_V2] 🔄 Event received: ${action}`, {
                record: flatRecord,
                original: record
            });

            // 1. Handle New Requests
            if (flatRecord && action === "LEAVE_REQUESTED") {
                setRequests(prev => {
                    if (prev.some(r => r.id === flatRecord.id)) return prev;
                    return [flatRecord, ...prev];
                });
                setTotalCount(prev => prev + 1);
                return;
            }

            // 2. Handle Updates
            const updateActions = ["LEAVE_UPDATED", "LEAVE_STATUS_CHANGED", "LEAVE_APPROVED", "LEAVE_REJECTED"];
            if (flatRecord && updateActions.includes(action)) {
                setRequests(prev => prev.map(r => r.id === flatRecord.id ? flatRecord : r));
                return;
            }

            // 3. Handle Deletions
            if (action === "LEAVE_DELETED") {
                const deletedId = record?.id || oldRecord?.id;
                if (deletedId) {
                    setRequests(prev => prev.filter(r => r.id !== deletedId));
                    setTotalCount(prev => Math.max(0, prev - 1));
                    return;
                }
            }

            // ⛔ BLOCK Fallback for all known leave actions to prevent the 10-item fetch
            if (action?.startsWith("LEAVE_")) {
                console.log(`[LeavesTable] ✅ Surgical update complete for ${action}. No fetch required.`);
                return;
            }

            // Fallback only for generic/unknown changes
            if (action === "team_update" || !action) {
                console.log(`[LeavesTable] ⚠️ Unknown action, falling back to fetch...`);
                fetchRequests(true, true);
            }
        };
        window.addEventListener("realtime-sync-refresh", handler);
        return () => window.removeEventListener("realtime-sync-refresh", handler);
    }, [workspaceId, pageIndex, pageSize]);

    const { setIsQuerying } = useTeamQueryStore();

    const fetchRequests = async (force = false, silent = false) => {
        try {
            setIsQuerying(true);
            if (!silent) setLoading(true);
            const res = await fetch(`/api/v1/attendance/leave-request?page=${pageIndex + 1}&pageSize=${pageSize}&search=${encodeURIComponent(debouncedSearch)}`, {
                headers: { "x-workspace-id": workspaceId }
            });
            const data = await res.json();
            if (data.success) {
                setRequests(data.data);
                setTotalCount(data.totalCount || 0);
            }
        } catch (error) {
            console.error("Failed to fetch leave requests:", error);
        } finally {
            setLoading(false);
            setIsQuerying(false);
        }
    };

    useEffect(() => {
        fetchRequests();
    }, [workspaceId, pageIndex, pageSize, debouncedSearch]);

    const handleUpdateStatus = async (id: string, status: "APPROVED" | "REJECTED") => {
        try {
            const res = await fetch(`/api/v1/attendance/leave-request/${id}`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                    "x-workspace-id": workspaceId
                },
                body: JSON.stringify({ status })
            });
            const data = await res.json();
            if (data.success) {
                toast.success(`Leave request ${status.toLowerCase()} successfully`);
                // Rely on real-time event for UI update
            } else {
                toast.error(data.error || `Failed to ${status.toLowerCase()} leave request`);
            }
        } catch (error) {
            toast.error("An error occurred");
        }
    };

    const columns = useMemo<ColumnDef<LeaveRequest>[]>(() => [
        {
            id: "member",
            header: "Member",
            cell: ({ row }) => {
                const leave = row.original;
                const initials = (leave.name?.[0] || leave.surname?.[0]).toUpperCase();

                return (
                    <Dialog>
                        <DialogTrigger asChild>
                            <div className="flex items-center gap-3 cursor-pointer group">
                                <Avatar className="h-9 w-9">
                                    <AvatarFallback>{initials}</AvatarFallback>
                                </Avatar>
                                <div className="flex flex-col">
                                    <span className="font-medium text-sm group-hover:text-primary transition-colors">
                                        {leave.surname}
                                    </span>
                                    <div className="flex items-center gap-2">
                                        <span className="text-[10px] text-muted-foreground bg-muted px-1.5 py-0.5 rounded uppercase font-medium">
                                            Bal: {leave.type === "CASUAL" ? `C:${leave.casualLeaveBalance}` : `S:${leave.sickLeaveBalance}`}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        </DialogTrigger>
                        <DialogContent className="sm:max-w-[500px] rounded-3xl border-none shadow-2xl overflow-hidden p-0">
                            <div className="p-8 space-y-6">
                                <DialogHeader className="flex flex-row items-center gap-4">
                                    <Avatar className="h-16 w-16 border-2 border-primary/20">
                                        <AvatarFallback className="text-xl font-medium">{initials}</AvatarFallback>
                                    </Avatar>
                                    <div>
                                        <DialogTitle className="text-2xl font-medium">{leave.name} {leave.surname}</DialogTitle>
                                        <p className="text-sm text-muted-foreground font-medium">{leave.email}</p>
                                    </div>
                                </DialogHeader>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="p-4 rounded-2xl bg-muted/30 border border-muted-foreground/5 space-y-1">
                                        <p className="text-[10px] font-medium uppercase text-muted-foreground tracking-widest">Leave Type</p>
                                        <p className="font-medium flex items-center gap-2 capitalize">
                                            <span className={cn("h-2 w-2 rounded-full", leave.type === 'SICK' ? "bg-rose-500" : "bg-blue-500")} />
                                            {leave.type.toLowerCase()} Leave
                                        </p>
                                    </div>
                                    <div className="p-4 rounded-2xl bg-muted/30 border border-muted-foreground/5 space-y-1">
                                        <p className="text-[10px] font-medium uppercase text-muted-foreground tracking-widest">Status</p>
                                        <p className="font-medium capitalize">{leave.status.toLowerCase()}</p>
                                    </div>
                                    <div className="col-span-2 p-4 rounded-2xl bg-muted/30 border border-muted-foreground/5 space-y-1">
                                        <p className="text-[10px] font-medium uppercase text-muted-foreground tracking-widest">Duration</p>
                                        <p className="font-medium">
                                            {format(new Date(leave.startDate), "MMMM d")} - {format(new Date(leave.endDate), "MMMM d, yyyy")}
                                        </p>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <p className="text-[10px] font-medium uppercase text-muted-foreground tracking-widest">Reason for Application</p>
                                    <div className="p-5 rounded-2xl bg-muted/50 border border-dashed border-muted-foreground/20 italic text-sm leading-relaxed text-muted-foreground">
                                        "{leave.reason}"
                                    </div>
                                </div>
                                
                                {leave.status !== "PENDING" && leave.processedByName && (
                                    <div className="p-4 rounded-2xl bg-muted/30 border border-muted-foreground/5 space-y-1">
                                        <p className="text-[10px] font-medium uppercase text-muted-foreground tracking-widest">
                                            {leave.status === "APPROVED" ? "Approved By" : "Rejected By"}
                                        </p>
                                        <p className="font-medium">{leave.processedByName}</p>
                                    </div>
                                )}

                                {leave.status === "PENDING" && (isOwnerOrAdmin || leave.reportToId === currentMemberId) && (
                                    <div className="flex gap-3 pt-4">
                                        <Button
                                            className="flex-1 rounded-2xl h-12 bg-emerald-600 hover:bg-emerald-700 font-medium"
                                            onClick={() => handleUpdateStatus(leave.id, "APPROVED")}
                                        >
                                            Approve Request
                                        </Button>
                                        <Button
                                            variant="outline"
                                            className="flex-1 rounded-2xl h-12 border-rose-200 text-rose-600 hover:bg-rose-50 font-medium"
                                            onClick={() => handleUpdateStatus(leave.id, "REJECTED")}
                                        >
                                            Reject
                                        </Button>
                                    </div>
                                )}
                            </div>
                        </DialogContent>
                    </Dialog>
                );
            },
        },
        {
            id: "type",
            header: "Type",
            cell: ({ row }) => {
                const type = row.original.type;
                return (
                    <Badge variant="outline" className={cn(
                        "font-medium uppercase text-[10px] tracking-wider",
                        type === "SICK" ? "border-rose-200 text-rose-600 bg-rose-50/50" : "border-blue-200 text-blue-600 bg-blue-50/50"
                    )}>
                        {type}
                    </Badge>
                );
            }
        },
        {
            id: "dates",
            header: "Duration",
            cell: ({ row }) => {
                const start = new Date(row.original.startDate);
                const end = new Date(row.original.endDate);
                const diffTime = Math.abs(end.getTime() - start.getTime());
                const days = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;

                return (
                    <div className="flex flex-col gap-1">
                        <div className="flex items-center gap-1.5 text-sm font-medium">
                            <CalendarIcon className="h-3.5 w-3.5 text-muted-foreground" />
                            {format(start, "MMM d")} - {format(end, "MMM d, yyyy")}
                        </div>
                        <span className="text-[10px] font-medium text-muted-foreground uppercase">
                            {days} {days === 1 ? 'Day' : 'Days'}
                        </span>
                    </div>
                );
            },
        },
        {
            accessorKey: "reason",
            header: "Reason",
            cell: ({ row }) => (
                <div className="max-w-[200px] truncate text-sm text-muted-foreground group relative">
                    <TooltipProvider>
                        <Tooltip>
                            <TooltipTrigger asChild>
                                <span className="cursor-help">{row.original.reason}</span>
                            </TooltipTrigger>
                            <TooltipContent className="max-w-xs bg-popover text-popover-foreground border shadow-xl p-3 rounded-xl">
                                <p className="text-xs leading-relaxed">{row.original.reason}</p>
                            </TooltipContent>
                        </Tooltip>
                    </TooltipProvider>
                </div>
            )
        },
        {
            accessorKey: "status",
            header: "Status",
            cell: ({ row }) => {
                const status = row.original.status;
                let content;
                switch (status) {
                    case "APPROVED":
                        content = <Badge className="bg-emerald-500/10 text-emerald-600 hover:bg-emerald-500/20 border-emerald-500/20 px-2.5 py-0.5 rounded-full font-medium">Approved</Badge>;
                        break;
                    case "REJECTED":
                        content = <Badge variant="destructive" className="px-2.5 py-0.5 rounded-full font-medium">Rejected</Badge>;
                        break;
                    case "PENDING":
                    default:
                        content = <Badge className="bg-amber-500/10 text-amber-600 hover:bg-amber-500/20 border-amber-500/20 px-2.5 py-0.5 rounded-full font-medium">Pending</Badge>;
                }
                return content;
            },
        },
        {
            id: "processedBy",
            header: "Processed By",
            cell: ({ row }) => {
                const processedByName = row.original.processedByName;
                if (!processedByName) return <span className="text-muted-foreground text-[10px]">—</span>;
                return (
                    <div className="flex items-center gap-1.5">
                        <User className="h-3 w-3 text-muted-foreground" />
                        <span className="text-[10px] font-medium text-muted-foreground uppercase">{processedByName}</span>
                    </div>
                );
            }
        },
        {
            id: "actions",
            header: () => <div className="text-right">Actions</div>,
            cell: ({ row }) => {
                const leave = row.original;
                const canManage = isOwnerOrAdmin || leave.reportToId === currentMemberId;

                if (!canManage || leave.status !== "PENDING") return null;

                return (
                    <div className="flex items-center justify-end gap-2">
                        <Button
                            size="sm"
                            variant="outline"
                            className="h-8 w-8 p-0 rounded-full border-emerald-200 text-emerald-600 hover:bg-emerald-50 hover:text-emerald-700 transition-all active:scale-90"
                            onClick={() => handleUpdateStatus(row.original.id, "APPROVED")}
                        >
                            <Check className="h-4 w-4" />
                        </Button>
                        <Button
                            size="sm"
                            variant="outline"
                            className="h-8 w-8 p-0 rounded-full border-rose-200 text-rose-600 hover:bg-rose-50 hover:text-rose-700 transition-all active:scale-90"
                            onClick={() => handleUpdateStatus(row.original.id, "REJECTED")}
                        >
                            <X className="h-4 w-4" />
                        </Button>
                    </div>
                );
            }
        }
    ], [isOwnerOrAdmin, currentMemberId, mounted]);

    if (!mounted) return null;

    return (
        <div className="space-y-4">
            <DataTable
                columns={columns}
                data={requests}
                isLoading={loading}
                searchKey="member"
                searchPlaceholder="Search by member..."
                pageIndex={pageIndex}
                pageSize={pageSize}
                rowCount={totalCount}
                manualPagination={true}
                manualFiltering={true}
                onPaginationChange={(p) => {
                    setPageIndex(p.pageIndex);
                    setPageSize(p.pageSize);
                }}
                onFilterChange={(filters) => {
                    const searchFilter = filters.find(f => f.id === "member");
                    const searchValue = searchFilter?.value as string || "";
                    setSearch(searchValue);
                }}
            />
        </div>
    );
}

