"use client";

import { useState, useTransition, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem } from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Badge } from "@/components/ui/badge";
import { Check, Loader2, Plus, Trash2, Users } from "lucide-react";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import { tryCatch } from "@/hooks/try-catch";
import { projectsClient } from "@/lib/api-client/projects";
import type { ProjectRole } from "@/generated/prisma/client";
import { type WorkspaceMembersResult } from "@/types/workspace";


interface ProjectMember {
    id: string;
    userId: string;
    userName: string;
    projectRole: ProjectRole;
}

interface ManageProjectMembersDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    projectId: string;
    projectName: string;
    currentMembers: ProjectMember[];
    workspaceMembers: WorkspaceMembersResult["workspaceMembers"];
}

export const ManageProjectMembersDialog = ({
    open,
    onOpenChange,
    projectId,
    projectName,
    currentMembers: initialMembers,
    workspaceMembers,
}: ManageProjectMembersDialogProps) => {
    const [pending, startTransition] = useTransition();
    const [selectedMembersToAdd, setSelectedMembersToAdd] = useState<string[]>([]);
    const [memberToRemove, setMemberToRemove] = useState<{ userId: string; name: string } | null>(null);
    // Local members state — seeded from props, updated immediately on action success
    const [members, setMembers] = useState<ProjectMember[]>(initialMembers);
    const router = useRouter();

    // Sync local state when server data (props) change or dialog opens
    // We use a JSON string of IDs as a stable dependency to avoid the 'size change' error
    // and prevent infinite loops from array reference changes
    const memberIdsHash = JSON.stringify(initialMembers.map(m => m.userId));
    useEffect(() => {
        setMembers(initialMembers);
    }, [memberIdsHash, open]);

    // Derived: which workspace members are not yet in the project (excluding OWNER/ADMIN)
    const currentMemberUserIds = new Set(members.map((m) => m.userId));
    const availableMembers = workspaceMembers.filter(
        (wm) => !currentMemberUserIds.has(wm.userId) && wm.workspaceRole !== "OWNER" && wm.workspaceRole !== "ADMIN"
    );

    const handleAddMembers = () => {
        if (selectedMembersToAdd.length === 0) {
            toast.error("Please select at least one member to add.");
            return;
        }

        startTransition(async () => {
            const { data: result, error } = await tryCatch(
                projectsClient.addMembers(projectId, selectedMembersToAdd)
            );

            if (error) {
                toast.error(error.message);
                console.error(error);
                return;
            }

            if (result.success) {
                toast.success(result.message || "Members added successfully!");
                // Optimistic update — add newly selected members immediately
                const newEntries: ProjectMember[] = selectedMembersToAdd
                    .map((userId) => {
                        const wm = workspaceMembers.find((m) => m.userId === userId);
                        if (!wm) return null;
                        return {
                            id: `temp-${userId}`,
                            userId,
                            userName: wm.surname || "Unknown",
                            projectRole: "MEMBER" as ProjectRole,
                        };
                    })
                    .filter(Boolean) as ProjectMember[];
                setMembers((prev) => [...prev, ...newEntries]);
                setSelectedMembersToAdd([]);
                router.refresh();
            } else {
                toast.error(result.message || "Failed to add members");
            }
        });
    };

    const handleRemoveMember = (memberUserId: string) => {
        startTransition(async () => {
            const { data: result, error } = await tryCatch(
                projectsClient.removeMembers(projectId, [memberUserId])
            );

            if (error) {
                toast.error(error.message);
                console.error(error);
                return;
            }

            if (result.success) {
                toast.success(result.message || "Member removed successfully!");
                // Optimistic update — remove immediately from local list
                setMembers((prev) => prev.filter((m) => m.userId !== memberUserId));
                router.refresh();
            } else {
                toast.error(result.message || "Failed to remove member");
            }
        });
    };

    const handleUpdateRole = (memberUserId: string, newRole: ProjectRole) => {
        startTransition(async () => {
            const { data: result, error } = await tryCatch(
                projectsClient.updateMemberRole(projectId, memberUserId, newRole)
            );

            if (error) {
                toast.error(error.message);
                console.error(error);
                return;
            }

            if (result.success) {
                toast.success(result.message || "Role updated successfully!");
                // Optimistic update — update role immediately in local list
                setMembers((prev) =>
                    prev.map((m) =>
                        m.userId === memberUserId ? { ...m, projectRole: newRole } : m
                    )
                );
                router.refresh();
            } else {
                toast.error(result.message || "Failed to update role");
            }
        });
    };

    return (
        <>
            <Dialog open={open} onOpenChange={onOpenChange}>
                <DialogContent className="max-h-[90vh] w-[min(700px,95vw)] overflow-hidden">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <Users className="h-5 w-5" />
                            Manage Project Members
                        </DialogTitle>
                        <DialogDescription>
                            Manage members for <strong>{projectName}</strong>
                        </DialogDescription>
                    </DialogHeader>

                    <div className="space-y-6 overflow-y-auto max-h-[60vh] thin-scrollbar px-2">
                        {/* Add Members Section */}
                        <div className="space-y-3">
                            <h3 className="text-sm font-semibold">Add Members</h3>
                            <div className="flex gap-2">
                                <Popover>
                                    <PopoverTrigger asChild>
                                        <Button
                                            variant="outline"
                                            className="flex-1 justify-between font-normal"
                                            disabled={pending || availableMembers.length === 0}
                                        >
                                            {selectedMembersToAdd.length > 0 ? (
                                                <span className="truncate">
                                                    {selectedMembersToAdd.length} member(s) selected
                                                </span>
                                            ) : availableMembers.length === 0 ? (
                                                "No available members"
                                            ) : (
                                                "Select members to add"
                                            )}
                                        </Button>
                                    </PopoverTrigger>

                                    <PopoverContent className="p-0 w-64">
                                        <Command>
                                            <CommandInput placeholder="Search members…" />
                                            <CommandEmpty>No members found.</CommandEmpty>
                                            <CommandGroup className="max-h-64 overflow-auto">
                                                {availableMembers.map((member) => {
                                                    const userName = member.surname || "Unknown";
                                                    const isSelected = selectedMembersToAdd.includes(
                                                        member.userId
                                                    );

                                                    return (
                                                        <CommandItem
                                                            key={member.userId}
                                                            value={userName}
                                                            onSelect={() => {
                                                                if (isSelected) {
                                                                    setSelectedMembersToAdd(
                                                                        selectedMembersToAdd.filter(
                                                                            (id) => id !== member.userId
                                                                        )
                                                                    );
                                                                } else {
                                                                    setSelectedMembersToAdd([
                                                                        ...selectedMembersToAdd,
                                                                        member.userId,
                                                                    ]);
                                                                }
                                                            }}
                                                        >
                                                            <Check
                                                                className={cn(
                                                                    "mr-2 h-4 w-4",
                                                                    isSelected
                                                                        ? "opacity-100"
                                                                        : "opacity-0"
                                                                )}
                                                            />
                                                            {userName}
                                                            <Badge
                                                                variant="outline"
                                                                className="ml-auto text-xs"
                                                            >
                                                                {member.workspaceRole}
                                                            </Badge>
                                                        </CommandItem>
                                                    );
                                                })}
                                            </CommandGroup>
                                        </Command>
                                    </PopoverContent>
                                </Popover>

                                <Button
                                    onClick={handleAddMembers}
                                    disabled={pending || selectedMembersToAdd.length === 0}
                                    size="default"
                                >
                                    {pending ? (
                                        <Loader2 className="h-4 w-4 animate-spin" />
                                    ) : (
                                        <>
                                            <Plus className="h-4 w-4 mr-1" />
                                            Add
                                        </>
                                    )}
                                </Button>
                            </div>
                        </div>

                        {/* Current Members Section */}
                        <div className="space-y-3">
                            <h3 className="text-sm font-semibold">
                                Current Members ({members.filter((member: ProjectMember) => {
                                    const workspaceMember = workspaceMembers.find(wm => wm.userId === member.userId);
                                    return workspaceMember?.workspaceRole !== "ADMIN" && workspaceMember?.workspaceRole !== "OWNER";
                                }).length})
                            </h3>
                            <div className="space-y-2">
                                {members.filter((member: ProjectMember) => {
                                    // Filter out workspace admins and owners from display
                                    const workspaceMember = workspaceMembers.find(wm => wm.userId === member.userId);
                                    return workspaceMember?.workspaceRole !== "ADMIN" && workspaceMember?.workspaceRole !== "OWNER";
                                }).length === 0 ? (
                                    <p className="text-sm text-muted-foreground text-center py-4">
                                        No members in this project yet.
                                    </p>
                                ) : (
                                    members
                                        .filter((member: ProjectMember) => {
                                            // Filter out workspace admins and owners from display
                                            const workspaceMember = workspaceMembers.find(wm => wm.userId === member.userId);
                                            return workspaceMember?.workspaceRole !== "ADMIN" && workspaceMember?.workspaceRole !== "OWNER";
                                        })
                                        .map((member: ProjectMember) => (
                                            <div
                                                key={member.id}
                                                className="flex items-center justify-between p-3 border rounded-lg hover:bg-accent/50 transition-colors"
                                            >
                                                <div className="flex items-center gap-3 flex-1 min-w-0">
                                                    <div className="flex-1 min-w-0">
                                                        <p className="text-sm font-medium truncate">
                                                            {member.userName}
                                                        </p>
                                                        <div className="flex items-center gap-2 mt-1">
                                                            <Badge
                                                                variant={
                                                                    member.projectRole === "PROJECT_MANAGER"
                                                                        ? "default"
                                                                        : member.projectRole === "LEAD"
                                                                            ? "secondary"
                                                                            : "outline"
                                                                }
                                                                className={cn(
                                                                    "text-xs",
                                                                    member.projectRole === "PROJECT_MANAGER" && "bg-amber-500 hover:bg-amber-600"
                                                                )}
                                                            >
                                                                {member.projectRole === "PROJECT_MANAGER" ? "Manager" : member.projectRole}
                                                            </Badge>
                                                        </div>
                                                    </div>
                                                </div>

                                                <div className="flex items-center gap-2">
                                                    {/* Role Selector - Only show for non-PROJECT_MANAGER roles */}
                                                    {member.projectRole !== "PROJECT_MANAGER" ? (
                                                        <Select
                                                            value={member.projectRole}
                                                            onValueChange={(value) =>
                                                                handleUpdateRole(member.userId, value as ProjectRole)
                                                            }
                                                            disabled={pending}
                                                        >
                                                            <SelectTrigger className="w-28 h-8 text-xs">
                                                                <SelectValue />
                                                            </SelectTrigger>
                                                            <SelectContent>
                                                                <SelectItem value="LEAD">Lead</SelectItem>
                                                                <SelectItem value="MEMBER">Member</SelectItem>
                                                                <SelectItem value="VIEWER">Viewer</SelectItem>
                                                            </SelectContent>
                                                        </Select>
                                                    ) : (
                                                        <div className="w-28 h-8 flex items-center justify-center text-xs text-muted-foreground">
                                                            Fixed Role
                                                        </div>
                                                    )}

                                                    {/* Remove Button - Disabled for PROJECT_MANAGER */}
                                                    <Button
                                                        variant="destructive"
                                                        size="sm"
                                                        onClick={() => setMemberToRemove({ userId: member.userId, name: member.userName })}
                                                        disabled={pending || member.projectRole === "PROJECT_MANAGER"}
                                                        className="h-8"
                                                        title={member.projectRole === "PROJECT_MANAGER" ? "Cannot remove project manager" : "Remove member"}
                                                    >
                                                        <Trash2 className="h-3 w-3" />
                                                    </Button>
                                                </div>
                                            </div>
                                        ))
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="flex justify-end pt-4 border-t">
                        <Button
                            variant="outline"
                            onClick={() => onOpenChange(false)}
                            disabled={pending}
                        >
                            Close
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>

            {/* Remove Member Confirmation — only mounted when needed to avoid Radix ID hydration shift */}
            {memberToRemove && (
                <AlertDialog open={true} onOpenChange={(open) => { if (!open) setMemberToRemove(null); }}>
                    <AlertDialogContent>
                        <AlertDialogHeader>
                            <AlertDialogTitle>Remove Member</AlertDialogTitle>
                            <AlertDialogDescription>
                                Are you sure you want to remove{" "}
                                <span className="font-semibold">{memberToRemove.name}</span>{" "}
                                from <span className="font-semibold">{projectName}</span>? They will lose
                                access to all tasks in this project.
                            </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                            <AlertDialogCancel disabled={pending}>Cancel</AlertDialogCancel>
                            <AlertDialogAction
                                disabled={pending}
                                className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                                onClick={() => {
                                    handleRemoveMember(memberToRemove.userId);
                                    setMemberToRemove(null);
                                }}
                            >
                                {pending ? <Loader2 className="h-4 w-4 animate-spin" /> : "Remove Member"}
                            </AlertDialogAction>
                        </AlertDialogFooter>
                    </AlertDialogContent>
                </AlertDialog>
            )}
        </>
    );
};

"use client";

import * as React from "react";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { DataTableFacetedFilter } from "./data-table-faceted-filter";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { ChevronLeft, ChevronRight, Columns, Search, Plus, X, Filter } from "lucide-react";
import { ColumnDef, ColumnFiltersState, SortingState, VisibilityState, flexRender, getCoreRowModel, getFilteredRowModel, getPaginationRowModel, getSortedRowModel, getFacetedRowModel, getFacetedUniqueValues, useReactTable } from "@tanstack/react-table";
import { DropdownMenu, DropdownMenuCheckboxItem, DropdownMenuContent, DropdownMenuTrigger, DropdownMenuSub, DropdownMenuSubTrigger, DropdownMenuSubContent, DropdownMenuSeparator, DropdownMenuItem } from "@/components/ui/dropdown-menu";
import { useMounted } from "@/hooks/use-mounted";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { cn } from "@/lib/utils";

export interface DataTableFilterField<TData> {
    label: string;
    value: string;
    options?: {
        label: string;
        value: string;
        icon?: React.ComponentType<{ className?: string }>;
    }[];
}

interface DataTableProps<TData, TValue> {
    columns: ColumnDef<TData, TValue>[];
    data: TData[];
    searchKey?: string;
    searchPlaceholder?: string;
    isLoading?: boolean;
    onRowClick?: (row: TData) => void;
    showPagination?: boolean;
    showColumnToggle?: boolean;
    pageSize?: number;
    pageIndex?: number;
    rowCount?: number;
    manualPagination?: boolean;
    onAdd?: () => void;
    addButtonLabel?: string;
    filterFields?: DataTableFilterField<TData>[];
    rowSelection?: Record<string, boolean>;
    onRowSelectionChange?: (value: any) => void;
    filterDisplay?: "default" | "menu";
    enableRowSelection?: (row: any) => boolean;
    getRowClassName?: (row: any) => string;
    extraToolbarContent?: React.ReactNode;
    onFilterChange?: (filters: ColumnFiltersState) => void;
    onPaginationChange?: (pagination: { pageIndex: number; pageSize: number }) => void;
    manualFiltering?: boolean;
    containerClassName?: string;
}

export function DataTable<TData, TValue>({
    columns,
    data,
    searchKey,
    searchPlaceholder = "Search...",
    isLoading = false,
    onRowClick,
    showPagination = true,
    showColumnToggle = true,
    pageSize = 10,
    pageIndex = 0,
    rowCount,
    manualPagination = false,
    manualFiltering = false,
    onAdd,
    addButtonLabel = "Add New",
    filterDisplay = "default",
    filterFields = [],
    rowSelection: controlledRowSelection,
    onRowSelectionChange: controlledOnRowSelectionChange,
    getRowId,
    enableRowSelection,
    getRowClassName,
    extraToolbarContent,
    onFilterChange,
    onPaginationChange,
    containerClassName,
}: DataTableProps<TData, TValue> & { getRowId?: (row: TData) => string }) {
    const [sorting, setSorting] = React.useState<SortingState>([]);
    const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([]);
    const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({});
    const [internalRowSelection, setInternalRowSelection] = React.useState({});
    const mounted = useMounted();

    const rowSelection = controlledRowSelection ?? internalRowSelection;
    const setRowSelection = controlledOnRowSelectionChange ?? setInternalRowSelection;

    // eslint-disable-next-line react-hooks/incompatible-library
    const table = useReactTable({
        data,
        columns,
        getCoreRowModel: getCoreRowModel(),
        getPaginationRowModel: (showPagination && !manualPagination) ? getPaginationRowModel() : undefined,
        manualPagination,
        manualFiltering,
        rowCount,
        onPaginationChange: (updater) => {
            if (onPaginationChange) {
                const current = { pageIndex, pageSize };
                const next = typeof updater === 'function' ? updater(current) : updater;
                onPaginationChange(next);
            }
        },
        onSortingChange: setSorting,
        getSortedRowModel: getSortedRowModel(),
        onColumnFiltersChange: (updater) => {
            const newFilters = typeof updater === 'function' ? updater(columnFilters) : updater;
            setColumnFilters(newFilters);
            onFilterChange?.(newFilters);
        },
        getFilteredRowModel: getFilteredRowModel(),
        getFacetedRowModel: getFacetedRowModel(),
        getFacetedUniqueValues: getFacetedUniqueValues(),
        onColumnVisibilityChange: setColumnVisibility,
        onRowSelectionChange: setRowSelection,
        getRowId,
        enableRowSelection,
        state: {
            sorting,
            columnFilters,
            columnVisibility,
            rowSelection,
            pagination: {
                pageIndex,
                pageSize,
            },
        },
    });

    return (
        <div className="space-y-4">
            {/* Toolbar */}
            {(searchKey || (filterFields && filterFields.length > 0) || extraToolbarContent || showColumnToggle) && (
                <div className="flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-3 sm:gap-4">
                    {/* Search */}
                    {searchKey && (
                        <div className="flex items-center flex-1 max-w-sm w-full">
                            <div className="relative w-full">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder={searchPlaceholder}
                                    value={(table.getColumn(searchKey)?.getFilterValue() as string) ?? ""}
                                    onChange={(event) =>
                                        table.getColumn(searchKey)?.setFilterValue(event.target.value)
                                    }
                                    className="pl-9 w-full h-9 bg-background/50 border-muted-foreground/20 focus:ring-primary/20"
                                />
                            </div>
                        </div>
                    )}

                    <div className="flex items-center gap-2 pb-1 sm:pb-0">

                        {filterDisplay === "menu" && mounted ? (
                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                    <Button variant="outline" size="sm" className="h-8 border-dashed">
                                        <Filter className="mr-2 h-4 w-4" />
                                        Filters
                                    </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align="start" className="w-[200px]">
                                    {filterFields.map((field) => {
                                        const column = table.getColumn(field.value);
                                        if (!column) return null;
                                        return (
                                            <DropdownMenuSub key={field.value}>
                                                <DropdownMenuSubTrigger>
                                                    {field.label}
                                                </DropdownMenuSubTrigger>
                                                <DropdownMenuSubContent className="w-[200px]">
                                                    {field.options?.map((option) => {
                                                        const filterValue = column.getFilterValue();
                                                        const isSelected = Array.isArray(filterValue)
                                                            ? filterValue.includes(option.value)
                                                            : filterValue === option.value;

                                                        return (
                                                            <DropdownMenuCheckboxItem
                                                                key={option.value}
                                                                checked={isSelected}
                                                                onCheckedChange={(checked) => {
                                                                    const current = (column.getFilterValue() as string[]) || [];
                                                                    if (checked) {
                                                                        column.setFilterValue([...current, option.value]);
                                                                    } else {
                                                                        column.setFilterValue(current.filter((v) => v !== option.value));
                                                                    }
                                                                }}
                                                            >
                                                                {option.label}
                                                            </DropdownMenuCheckboxItem>
                                                        );
                                                    })}
                                                    {(column.getFilterValue() as string[])?.length > 0 && (
                                                        <>
                                                            <DropdownMenuSeparator />
                                                            <DropdownMenuItem
                                                                onSelect={() => column.setFilterValue(undefined)}
                                                                className="justify-center text-center text-xs"
                                                            >
                                                                Clear
                                                            </DropdownMenuItem>
                                                        </>
                                                    )}
                                                </DropdownMenuSubContent>
                                            </DropdownMenuSub>
                                        );
                                    })}
                                    {(table.getState().columnFilters.length > 0) && (
                                        <>
                                            <DropdownMenuSeparator />
                                            <DropdownMenuItem
                                                onSelect={() => table.resetColumnFilters()}
                                                className="justify-center text-center"
                                            >
                                                Reset all
                                            </DropdownMenuItem>
                                        </>
                                    )}
                                </DropdownMenuContent>
                            </DropdownMenu>
                        ) : (
                            <>
                                {mounted && filterFields.map((field) => {
                                    const column = table.getColumn(field.value);
                                    return (
                                        column && (
                                            <DataTableFacetedFilter
                                                key={field.value}
                                                column={column}
                                                title={field.label}
                                                options={field.options || []}
                                            />
                                        )
                                    );
                                })}
                                {(table.getState().columnFilters.length > 0 || !!table.getState().globalFilter) && (
                                    <Button
                                        variant="ghost"
                                        onClick={() => table.resetColumnFilters()}
                                        className="h-8 px-2 lg:px-3"
                                    >
                                        Reset
                                        <X className="ml-2 h-4 w-4" />
                                    </Button>
                                )}
                            </>
                        )}

                        {extraToolbarContent}

                        {/* Column Toggle */}
                        {showColumnToggle && mounted && (
                            <DropdownMenu>
                                <DropdownMenuTrigger asChild>
                                    <Button variant="outline" size="sm" className="ml-auto h-9">
                                        <Columns className="mr-2 h-4 w-4" />
                                        Columns
                                    </Button>
                                </DropdownMenuTrigger>
                                <DropdownMenuContent align="end" className="w-[200px]">
                                    {table
                                        .getAllColumns()
                                        .filter((column) => column.getCanHide())
                                        .map((column) => {
                                            return (
                                                <DropdownMenuCheckboxItem
                                                    key={column.id}
                                                    className="capitalize"
                                                    checked={column.getIsVisible()}
                                                    onCheckedChange={(value) => column.toggleVisibility(!!value)}
                                                >
                                                    {typeof column.columnDef.header === 'string' 
                                                        ? column.columnDef.header 
                                                        : column.id}
                                                </DropdownMenuCheckboxItem>
                                            );
                                        })}
                                </DropdownMenuContent>
                            </DropdownMenu>
                        )}
                    </div>
                </div>
            )}

            {/* Active Filters Display for Menu Mode */}
            {filterDisplay === "menu" && table.getState().columnFilters.length > 0 && (
                <div className="flex flex-wrap gap-2 pb-2">
                    {filterFields.map((field) => {
                        const column = table.getColumn(field.value);
                        const filterValue = column?.getFilterValue() as string[] | undefined;

                        if (!filterValue || filterValue.length === 0) return null;

                        return filterValue.map((val) => {
                            const option = field.options?.find((o) => o.value === val);
                            return (
                                <Badge
                                    key={`${field.value}-${val}`}
                                    variant="secondary"
                                    className="rounded-sm px-1 font-normal"
                                >
                                    <span className="font-semibold mr-1">{field.label}:</span>
                                    {option?.label || val}
                                    <button
                                        className="ml-1 ring-offset-background focus:ring-ring rounded-full outline-none focus:ring-2 focus:ring-offset-2"
                                        onMouseDown={(e) => {
                                            e.preventDefault();
                                            e.stopPropagation();
                                        }}
                                        onClick={(e) => {
                                            e.preventDefault();
                                            e.stopPropagation();
                                            const newValues = filterValue.filter((v) => v !== val);
                                            column?.setFilterValue(
                                                newValues.length ? newValues : undefined
                                            );
                                        }}
                                    >
                                        <X className="h-3 w-3 hover:text-destructive" />
                                    </button>
                                </Badge>
                            );
                        });
                    })}
                    <Button
                        variant="ghost"
                        onClick={() => table.resetColumnFilters()}
                        className="h-6 px-2 text-xs"
                    >
                        Reset
                        <X className="ml-2 h-3 w-3" />
                    </Button>
                </div>
            )}


            {/* Table */}
            <div className={cn("rounded-md border overflow-hidden", containerClassName)}>
                <Table containerClassName="max-h-[inherit] overflow-auto">
                    <TableHeader className="sticky top-0 z-10 bg-background shadow-sm">
                            {table.getHeaderGroups().map((headerGroup) => (
                                <TableRow key={headerGroup.id}>
                                    {headerGroup.headers.map((header) => {
                                        return (
                                            <TableHead
                                                key={header.id}
                                                className={cn(
                                                    "text-[11px] font-bold uppercase tracking-widest text-muted-foreground/80 py-3 h-auto",
                                                    (header.column.columnDef.meta as { className?: string })?.className
                                                )}
                                            >
                                                {header.isPlaceholder
                                                    ? null
                                                    : flexRender(
                                                        header.column.columnDef.header,
                                                        header.getContext()
                                                    )}
                                            </TableHead>
                                        );
                                    })}
                                </TableRow>
                            ))}
                        </TableHeader>
                        <TableBody>
                            {isLoading ? (
                                Array.from({ length: pageSize }).map((_, index) => (
                                    <TableRow key={index}>
                                        {columns.map((_, cellIndex) => (
                                            <TableCell key={cellIndex}>
                                                <Skeleton className="h-6 w-full" />
                                            </TableCell>
                                        ))}
                                    </TableRow>
                                ))
                            ) : table.getRowModel().rows?.length ? (
                                table.getRowModel().rows.map((row) => (
                                    <TableRow
                                        key={row.id}
                                        data-state={row.getIsSelected() && "selected"}
                                        onClick={() => onRowClick?.(row.original)}
                                        className={`
                                        ${onRowClick ? "cursor-pointer" : ""}
                                        ${getRowClassName?.(row) || ""}
                                    `.trim()}
                                    >
                                        {row.getVisibleCells().map((cell) => (
                                            <TableCell
                                                key={cell.id}
                                                className={(cell.column.columnDef.meta as { className?: string })?.className}
                                            >
                                                {flexRender(cell.column.columnDef.cell, cell.getContext())}
                                            </TableCell>
                                        ))}
                                    </TableRow>
                                ))
                            ) : (
                                !onAdd && (
                                    <TableRow>
                                        <TableCell colSpan={columns.length} className="h-24 text-center">
                                            No results found.
                                        </TableCell>
                                    </TableRow>
                                )
                            )}
                            {/* Inline Add Button Row */}
                            {onAdd && !isLoading && (
                                <TableRow
                                    className="cursor-pointer hover:bg-muted/50 border-dashed border-b-0 group"
                                    onClick={onAdd}
                                >
                                    <TableCell colSpan={columns.length} className="p-2">
                                        <div className="flex items-center justify-center gap-2 h-9 text-primary font-medium transition-colors border-dashed border border-primary/50 bg-primary/5 rounded-md hover:bg-primary/10">
                                            <Plus className="h-4 w-4" />
                                            <span className="text-sm">{addButtonLabel}</span>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            )}
                        </TableBody>
                    </Table>
            </div>

            {/* Pagination */}
            {showPagination && (
                <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mt-2">
                    <div className="flex items-center gap-4 sm:gap-6 order-2 sm:order-1 w-full sm:w-auto justify-between sm:justify-start">
                        {/* Page Size Selector */}
                        <div className="flex items-center gap-2">
                            <p className="text-sm font-medium whitespace-nowrap">Rows per page</p>
                            <Select
                                value={`${table.getState().pagination.pageSize}`}
                                onValueChange={(value) => {
                                    table.setPageSize(Number(value));
                                }}
                            >
                                <SelectTrigger className="h-8 w-[70px]">
                                    <SelectValue placeholder={table.getState().pagination.pageSize} />
                                </SelectTrigger>
                                <SelectContent side="top">
                                    {[10, 20, 30, 40, 50].map((pageSize) => (
                                        <SelectItem key={pageSize} value={`${pageSize}`}>
                                            {pageSize}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>

                        {/* Page Count Info */}
                        <div className="flex w-[100px] items-center justify-center text-sm font-medium whitespace-nowrap">
                            Page {table.getState().pagination.pageIndex + 1} of{" "}
                            {table.getPageCount()}
                        </div>
                    </div>

                    <div className="flex items-center gap-2 order-1 sm:order-2 ml-auto">
                        <div className="flex items-center gap-2">
                            <Button
                                variant="outline"
                                className="hidden h-8 w-8 p-0 lg:flex"
                                onClick={() => table.setPageIndex(0)}
                                disabled={!table.getCanPreviousPage()}
                            >
                                <span className="sr-only">Go to first page</span>
                                <ChevronLeft className="h-4 w-4" />
                                <ChevronLeft className="h-4 w-4 -ml-2" />
                            </Button>
                            <Button
                                variant="outline"
                                className="h-8 w-8 p-0"
                                onClick={() => table.previousPage()}
                                disabled={!table.getCanPreviousPage()}
                            >
                                <span className="sr-only">Go to previous page</span>
                                <ChevronLeft className="h-4 w-4" />
                            </Button>

                            {/* Buffer Pages / Page Numbers */}
                            <div className="flex items-center gap-1">
                                {(() => {
                                    const currentPage = table.getState().pagination.pageIndex;
                                    const pageCount = table.getPageCount();
                                    const pages = [];

                                    // Simple logic for 5 pages around current
                                    let start = Math.max(0, currentPage - 2);
                                    let end = Math.min(pageCount - 1, start + 4);

                                    // Adjust start if end is at max
                                    if (end - start < 4) {
                                        start = Math.max(0, end - 4);
                                    }

                                    for (let i = start; i <= end; i++) {
                                        pages.push(
                                            <Button
                                                key={i}
                                                variant={currentPage === i ? "default" : "outline"}
                                                size="sm"
                                                className="h-8 w-8 p-0 hidden sm:flex"
                                                onClick={() => table.setPageIndex(i)}
                                            >
                                                {i + 1}
                                            </Button>
                                        );
                                    }
                                    return pages;
                                })()}
                            </div>

                            <Button
                                variant="outline"
                                className="h-8 w-8 p-0"
                                onClick={() => table.nextPage()}
                                disabled={!table.getCanNextPage()}
                            >
                                <span className="sr-only">Go to next page</span>
                                <ChevronRight className="h-4 w-4" />
                            </Button>
                            <Button
                                variant="outline"
                                className="hidden h-8 w-8 p-0 lg:flex"
                                onClick={() => table.setPageIndex(table.getPageCount() - 1)}
                                disabled={!table.getCanNextPage()}
                            >
                                <span className="sr-only">Go to last page</span>
                                <ChevronRight className="h-4 w-4" />
                                <ChevronRight className="h-4 w-4 -ml-2" />
                            </Button>
                        </div>
                    </div>

                    {/* Row Selection Info */}
                    <div className="hidden sm:block text-sm text-muted-foreground order-3 ml-4">
                        {table.getFilteredSelectedRowModel().rows.length > 0 && (
                            <span>
                                {table.getFilteredSelectedRowModel().rows.length} of{" "}
                                {table.getFilteredRowModel().rows.length} row(s) selected.
                            </span>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

